[
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.assign_permission_to_role(p_role_name character varying, p_permission_name character varying)\n RETURNS void\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_permission_id integer;\r\nBEGIN\r\n  -- Verificar se usuário é admin\r\n  IF NOT EXISTS (\r\n    SELECT 1 FROM public.profiles \r\n    WHERE id = auth.uid() \r\n    AND role = 'admin'\r\n  ) THEN\r\n    RAISE EXCEPTION 'Apenas administradores podem atribuir permissões';\r\n  END IF;\r\n  \r\n  -- Buscar ID da permissão\r\n  SELECT id INTO v_permission_id\r\n  FROM public.permissions\r\n  WHERE name = p_permission_name;\r\n  \r\n  IF NOT FOUND THEN\r\n    RAISE EXCEPTION 'Permissão \"%\" não encontrada', p_permission_name;\r\n  END IF;\r\n  \r\n  -- Inserir associação (ignorar se já existir)\r\n  INSERT INTO public.role_permissions (role_name, permission_id)\r\n  VALUES (p_role_name, v_permission_id)\r\n  ON CONFLICT (role_name, permission_id) DO NOTHING;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.revoke_permission_from_role(p_role_name character varying, p_permission_name character varying)\n RETURNS void\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_permission_id integer;\r\nBEGIN\r\n  -- Verificar se usuário é admin\r\n  IF NOT EXISTS (\r\n    SELECT 1 FROM public.profiles \r\n    WHERE id = auth.uid() \r\n    AND role = 'admin'\r\n  ) THEN\r\n    RAISE EXCEPTION 'Apenas administradores podem remover permissões';\r\n  END IF;\r\n  \r\n  -- Buscar ID da permissão\r\n  SELECT id INTO v_permission_id\r\n  FROM public.permissions\r\n  WHERE name = p_permission_name;\r\n  \r\n  IF NOT FOUND THEN\r\n    RAISE EXCEPTION 'Permissão \"%\" não encontrada', p_permission_name;\r\n  END IF;\r\n  \r\n  -- Remover associação\r\n  DELETE FROM public.role_permissions\r\n  WHERE role_name = p_role_name\r\n    AND permission_id = v_permission_id;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.check_rate_limit(p_action text, p_user_id uuid DEFAULT NULL::uuid, p_ip_address inet DEFAULT NULL::inet, p_max_requests integer DEFAULT 100, p_window_seconds integer DEFAULT 60)\n RETURNS boolean\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_count INT;\r\nBEGIN\r\n  -- Limpar registros antigos primeiro\r\n  DELETE FROM rate_limits \r\n  WHERE created_at < NOW() - (p_window_seconds || ' seconds')::INTERVAL;\r\n  \r\n  -- Contar requisições recentes\r\n  IF p_user_id IS NOT NULL THEN\r\n    SELECT COUNT(*) INTO v_count\r\n    FROM rate_limits\r\n    WHERE user_id = p_user_id \r\n      AND action = p_action\r\n      AND created_at > NOW() - (p_window_seconds || ' seconds')::INTERVAL;\r\n  ELSIF p_ip_address IS NOT NULL THEN\r\n    SELECT COUNT(*) INTO v_count\r\n    FROM rate_limits\r\n    WHERE ip_address = p_ip_address \r\n      AND action = p_action\r\n      AND created_at > NOW() - (p_window_seconds || ' seconds')::INTERVAL;\r\n  ELSE\r\n    RETURN TRUE;\r\n  END IF;\r\n  \r\n  -- Verificar limite\r\n  IF v_count >= p_max_requests THEN\r\n    RETURN FALSE;\r\n  END IF;\r\n  \r\n  -- Registrar requisição\r\n  INSERT INTO rate_limits (user_id, ip_address, action, created_at)\r\n  VALUES (p_user_id, p_ip_address, p_action, NOW());\r\n  \r\n  RETURN TRUE;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.create_notification(p_user_id uuid, p_title character varying, p_message text, p_type character varying DEFAULT 'info'::character varying, p_link text DEFAULT NULL::text, p_entity_id text DEFAULT NULL::text, p_entity_type character varying DEFAULT NULL::character varying)\n RETURNS uuid\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_notification_id uuid;\r\nBEGIN\r\n  -- Verificar se usuário existe\r\n  IF NOT EXISTS (SELECT 1 FROM auth.users WHERE id = p_user_id) THEN\r\n    RAISE EXCEPTION 'Usuário não encontrado';\r\n  END IF;\r\n  \r\n  -- Criar notificação\r\n  INSERT INTO public.notifications (\r\n    user_id,\r\n    title,\r\n    message,\r\n    type,\r\n    link,\r\n    entity_id,\r\n    entity_type,\r\n    read,\r\n    created_at\r\n  ) VALUES (\r\n    p_user_id,\r\n    p_title,\r\n    p_message,\r\n    p_type,\r\n    p_link,\r\n    p_entity_id,\r\n    p_entity_type,\r\n    false,\r\n    now()\r\n  )\r\n  RETURNING id INTO v_notification_id;\r\n  \r\n  RETURN v_notification_id;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.mark_notification_as_read(p_notification_id uuid)\n RETURNS boolean\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nBEGIN\r\n  UPDATE public.notifications\r\n  SET \r\n    read = true,\r\n    read_at = now(),\r\n    updated_at = now()\r\n  WHERE id = p_notification_id\r\n    AND user_id = auth.uid()\r\n    AND read = false;\r\n    \r\n  RETURN FOUND;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.mark_all_notifications_as_read()\n RETURNS integer\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_count integer;\r\nBEGIN\r\n  WITH updated AS (\r\n    UPDATE public.notifications\r\n    SET \r\n      read = true,\r\n      read_at = now(),\r\n      updated_at = now()\r\n    WHERE user_id = auth.uid()\r\n      AND read = false\r\n    RETURNING id\r\n  )\r\n  SELECT COUNT(*) INTO v_count FROM updated;\r\n  \r\n  RETURN v_count;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.cleanup_old_notifications(p_days integer DEFAULT 30)\n RETURNS integer\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_count integer;\r\nBEGIN\r\n  -- Apenas admins podem executar limpeza global\r\n  IF NOT EXISTS (\r\n    SELECT 1 FROM public.profiles \r\n    WHERE id = auth.uid() \r\n    AND role = 'admin'\r\n  ) THEN\r\n    RAISE EXCEPTION 'Apenas administradores podem executar limpeza';\r\n  END IF;\r\n  \r\n  WITH deleted AS (\r\n    DELETE FROM public.notifications\r\n    WHERE read = true\r\n      AND created_at < (now() - (p_days || ' days')::interval)\r\n    RETURNING id\r\n  )\r\n  SELECT COUNT(*) INTO v_count FROM deleted;\r\n  \r\n  RETURN v_count;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.get_unread_notifications_count()\n RETURNS integer\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_count integer;\r\nBEGIN\r\n  SELECT COUNT(*) INTO v_count\r\n  FROM public.notifications\r\n  WHERE user_id = auth.uid()\r\n    AND read = false;\r\n    \r\n  RETURN v_count;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.prevent_duplicate_notifications()\n RETURNS trigger\n LANGUAGE plpgsql\nAS $function$\r\nBEGIN\r\n  -- Verificar se já existe notificação similar nos últimos 5 minutos\r\n  IF EXISTS (\r\n    SELECT 1 FROM public.notifications\r\n    WHERE user_id = NEW.user_id\r\n      AND title = NEW.title\r\n      AND message = NEW.message\r\n      AND entity_id = NEW.entity_id\r\n      AND entity_type = NEW.entity_type\r\n      AND created_at > (now() - interval '5 minutes')\r\n  ) THEN\r\n    RETURN NULL; -- Ignorar inserção\r\n  END IF;\r\n  \r\n  RETURN NEW;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.sync_role_permissions(p_role_name character varying, p_permission_names text[])\n RETURNS void\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_permission_id integer;\r\n  v_permission_name text;\r\nBEGIN\r\n  -- Verificar se usuário é admin\r\n  IF NOT EXISTS (\r\n    SELECT 1 FROM public.profiles \r\n    WHERE id = auth.uid() \r\n    AND role = 'admin'\r\n  ) THEN\r\n    RAISE EXCEPTION 'Apenas administradores podem sincronizar permissões';\r\n  END IF;\r\n  \r\n  -- Iniciar transação\r\n  BEGIN\r\n    -- Remover todas as permissões atuais da role\r\n    DELETE FROM public.role_permissions\r\n    WHERE role_name = p_role_name;\r\n    \r\n    -- Inserir novas permissões\r\n    FOREACH v_permission_name IN ARRAY p_permission_names\r\n    LOOP\r\n      SELECT id INTO v_permission_id\r\n      FROM public.permissions\r\n      WHERE name = v_permission_name;\r\n      \r\n      IF FOUND THEN\r\n        INSERT INTO public.role_permissions (role_name, permission_id)\r\n        VALUES (p_role_name, v_permission_id);\r\n      END IF;\r\n    END LOOP;\r\n  EXCEPTION\r\n    WHEN OTHERS THEN\r\n      RAISE EXCEPTION 'Erro ao sincronizar permissões: %', SQLERRM;\r\n  END;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.get_role_permissions(p_role_name character varying)\n RETURNS TABLE(permission_id integer, permission_name character varying, module character varying, description text)\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nBEGIN\r\n  RETURN QUERY\r\n  SELECT \r\n    p.id,\r\n    p.name,\r\n    p.module,\r\n    p.description\r\n  FROM public.role_permissions rp\r\n  JOIN public.permissions p ON p.id = rp.permission_id\r\n  WHERE rp.role_name = p_role_name\r\n  ORDER BY p.module, p.name;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.clone_role_permissions(p_source_role character varying, p_target_role character varying)\n RETURNS integer\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_count integer;\r\nBEGIN\r\n  -- Verificar se usuário é admin\r\n  IF NOT EXISTS (\r\n    SELECT 1 FROM public.profiles \r\n    WHERE id = auth.uid() \r\n    AND role = 'admin'\r\n  ) THEN\r\n    RAISE EXCEPTION 'Apenas administradores podem clonar permissões';\r\n  END IF;\r\n  \r\n  -- Remover permissões atuais da role destino\r\n  DELETE FROM public.role_permissions\r\n  WHERE role_name = p_target_role;\r\n  \r\n  -- Copiar permissões da role origem\r\n  WITH inserted AS (\r\n    INSERT INTO public.role_permissions (role_name, permission_id)\r\n    SELECT p_target_role, permission_id\r\n    FROM public.role_permissions\r\n    WHERE role_name = p_source_role\r\n    RETURNING id\r\n  )\r\n  SELECT COUNT(*) INTO v_count FROM inserted;\r\n  \r\n  RETURN v_count;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.update_system_setting(p_setting_key text, p_value text)\n RETURNS void\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_settings_id uuid;\r\nBEGIN\r\n  -- Verificar permissão\r\n  IF NOT EXISTS (\r\n    SELECT 1 FROM public.profiles \r\n    WHERE id = auth.uid() \r\n    AND role = 'admin'\r\n  ) THEN\r\n    RAISE EXCEPTION 'Apenas administradores podem alterar configurações do sistema';\r\n  END IF;\r\n  \r\n  -- Buscar ID da configuração\r\n  SELECT id INTO v_settings_id FROM public.system_settings LIMIT 1;\r\n  \r\n  -- Se não existir, criar\r\n  IF NOT FOUND THEN\r\n    INSERT INTO public.system_settings DEFAULT VALUES\r\n    RETURNING id INTO v_settings_id;\r\n  END IF;\r\n  \r\n  -- Atualizar configuração específica\r\n  CASE p_setting_key\r\n    WHEN 'currency' THEN\r\n      UPDATE public.system_settings SET currency = p_value WHERE id = v_settings_id;\r\n    WHEN 'date_format' THEN\r\n      UPDATE public.system_settings SET date_format = p_value WHERE id = v_settings_id;\r\n    WHEN 'time_format' THEN\r\n      UPDATE public.system_settings SET time_format = p_value WHERE id = v_settings_id;\r\n    WHEN 'language' THEN\r\n      UPDATE public.system_settings SET language = p_value WHERE id = v_settings_id;\r\n    WHEN 'timezone' THEN\r\n      UPDATE public.system_settings SET timezone = p_value WHERE id = v_settings_id;\r\n    ELSE\r\n      RAISE EXCEPTION 'Configuração \"%\" não encontrada', p_setting_key;\r\n  END CASE;\r\n  \r\n  -- Registrar auditoria\r\n  PERFORM public.log_system_event(\r\n    'update_setting',\r\n    'system_settings',\r\n    v_settings_id::text,\r\n    NULL,\r\n    jsonb_build_object(p_setting_key, p_value),\r\n    jsonb_build_object('updated_by', auth.uid())\r\n  );\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.get_all_system_settings()\n RETURNS jsonb\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_settings record;\r\n  v_result jsonb;\r\nBEGIN\r\n  SELECT * INTO v_settings\r\n  FROM public.system_settings\r\n  LIMIT 1;\r\n  \r\n  IF NOT FOUND THEN\r\n    -- Retornar valores padrão\r\n    RETURN jsonb_build_object(\r\n      'currency', 'BRL',\r\n      'date_format', 'DD/MM/YYYY',\r\n      'time_format', '24h',\r\n      'language', 'pt-BR',\r\n      'timezone', 'America/Sao_Paulo'\r\n    );\r\n  END IF;\r\n  \r\n  RETURN to_jsonb(v_settings) - 'id' - 'updated_at';\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.initialize_system_settings()\n RETURNS uuid\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_settings_id uuid;\r\nBEGIN\r\n  -- Verificar permissão\r\n  IF NOT EXISTS (\r\n    SELECT 1 FROM public.profiles \r\n    WHERE id = auth.uid() \r\n    AND role = 'admin'\r\n  ) THEN\r\n    RAISE EXCEPTION 'Apenas administradores podem inicializar configurações';\r\n  END IF;\r\n  \r\n  -- Verificar se já existe\r\n  SELECT id INTO v_settings_id FROM public.system_settings LIMIT 1;\r\n  \r\n  IF FOUND THEN\r\n    RAISE EXCEPTION 'Configurações já inicializadas';\r\n  END IF;\r\n  \r\n  -- Criar configurações padrão\r\n  INSERT INTO public.system_settings (\r\n    currency,\r\n    date_format,\r\n    time_format,\r\n    language,\r\n    timezone\r\n  ) VALUES (\r\n    'BRL',\r\n    'DD/MM/YYYY',\r\n    '24h',\r\n    'pt-BR',\r\n    'America/Sao_Paulo'\r\n  )\r\n  RETURNING id INTO v_settings_id;\r\n  \r\n  RETURN v_settings_id;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.enforce_single_system_settings()\n RETURNS trigger\n LANGUAGE plpgsql\nAS $function$\r\nDECLARE\r\n  v_count integer;\r\nBEGIN\r\n  SELECT COUNT(*) INTO v_count FROM public.system_settings;\r\n  \r\n  IF v_count >= 1 AND TG_OP = 'INSERT' THEN\r\n    RAISE EXCEPTION 'Apenas um registro é permitido na tabela system_settings';\r\n  END IF;\r\n  \r\n  RETURN NEW;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.start_counting_item(p_item_id uuid)\n RETURNS void\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nBEGIN\r\n  UPDATE public.stock_count_items\r\n  SET \r\n    status = 'in_progress',\r\n    updated_at = now()\r\n  WHERE id = p_item_id\r\n    AND status = 'pending'\r\n    AND EXISTS (\r\n      SELECT 1 FROM public.stock_count_sessions scs\r\n      WHERE scs.id = count_session_id\r\n        AND scs.status = 'open'\r\n    );\r\n    \r\n  IF NOT FOUND THEN\r\n    RAISE EXCEPTION 'Item não encontrado ou não pode ser iniciado';\r\n  END IF;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.record_item_count(p_item_id uuid, p_counted_quantity numeric, p_notes text DEFAULT NULL::text)\n RETURNS void\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_system_quantity numeric;\r\n  v_difference numeric;\r\nBEGIN\r\n  -- Buscar quantidade do sistema\r\n  SELECT system_quantity INTO v_system_quantity\r\n  FROM public.stock_count_items\r\n  WHERE id = p_item_id;\r\n  \r\n  -- Calcular diferença\r\n  v_difference := p_counted_quantity - v_system_quantity;\r\n  \r\n  -- Atualizar item\r\n  UPDATE public.stock_count_items\r\n  SET \r\n    counted_quantity = p_counted_quantity,\r\n    difference = v_difference,\r\n    status = 'counted',\r\n    notes = COALESCE(p_notes, notes),\r\n    counted_by = auth.uid(),\r\n    counted_at = now(),\r\n    updated_at = now()\r\n  WHERE id = p_item_id\r\n    AND status IN ('pending', 'in_progress')\r\n    AND EXISTS (\r\n      SELECT 1 FROM public.stock_count_sessions scs\r\n      WHERE scs.id = count_session_id\r\n        AND scs.status = 'open'\r\n    );\r\n    \r\n  IF NOT FOUND THEN\r\n    RAISE EXCEPTION 'Item não encontrado ou já foi contado';\r\n  END IF;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.skip_count_item(p_item_id uuid, p_reason text DEFAULT NULL::text)\n RETURNS void\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nBEGIN\r\n  UPDATE public.stock_count_items\r\n  SET \r\n    status = 'skipped',\r\n    notes = COALESCE(p_reason, 'Item pulado durante contagem'),\r\n    updated_at = now()\r\n  WHERE id = p_item_id\r\n    AND status IN ('pending', 'in_progress')\r\n    AND EXISTS (\r\n      SELECT 1 FROM public.stock_count_sessions scs\r\n      WHERE scs.id = count_session_id\r\n        AND scs.status = 'open'\r\n    );\r\n    \r\n  IF NOT FOUND THEN\r\n    RAISE EXCEPTION 'Item não encontrado ou já foi processado';\r\n  END IF;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.get_count_session_summary(p_session_id uuid)\n RETURNS jsonb\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_result jsonb;\r\nBEGIN\r\n  SELECT jsonb_build_object(\r\n    'total_items', COUNT(*),\r\n    'pending', COUNT(*) FILTER (WHERE status = 'pending'),\r\n    'in_progress', COUNT(*) FILTER (WHERE status = 'in_progress'),\r\n    'counted', COUNT(*) FILTER (WHERE status = 'counted'),\r\n    'skipped', COUNT(*) FILTER (WHERE status = 'skipped'),\r\n    'with_difference', COUNT(*) FILTER (WHERE difference != 0),\r\n    'total_difference_value', COALESCE(SUM(difference * system_cost), 0)\r\n  )\r\n  INTO v_result\r\n  FROM public.stock_count_items\r\n  WHERE count_session_id = p_session_id;\r\n  \r\n  RETURN v_result;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.calculate_item_difference()\n RETURNS trigger\n LANGUAGE plpgsql\nAS $function$\r\nBEGIN\r\n  -- Calcular diferença quando quantidade contada é informada\r\n  IF NEW.counted_quantity IS NOT NULL AND OLD.counted_quantity IS DISTINCT FROM NEW.counted_quantity THEN\r\n    NEW.difference := NEW.counted_quantity - NEW.system_quantity;\r\n  END IF;\r\n  \r\n  -- Se estiver finalizando, garantir que tem counted_by e counted_at\r\n  IF NEW.status = 'counted' AND OLD.status != 'counted' THEN\r\n    IF NEW.counted_quantity IS NULL THEN\r\n      RAISE EXCEPTION 'Quantidade contada é obrigatória para finalizar item';\r\n    END IF;\r\n  END IF;\r\n  \r\n  RETURN NEW;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.log_system_event(p_action text, p_entity_type text DEFAULT NULL::text, p_entity_id text DEFAULT NULL::text, p_old_data jsonb DEFAULT NULL::jsonb, p_new_data jsonb DEFAULT NULL::jsonb, p_details jsonb DEFAULT NULL::jsonb)\n RETURNS uuid\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_log_id uuid;\r\n  v_user_email text;\r\n  v_user_role text;\r\n  v_ip_address text;\r\n  v_user_agent text;\r\nBEGIN\r\n  -- Buscar informações do usuário atual\r\n  SELECT email, role INTO v_user_email, v_user_role\r\n  FROM public.profiles\r\n  WHERE id = auth.uid();\r\n  \r\n  -- Buscar IP e User-Agent (se disponível)\r\n  BEGIN\r\n    v_ip_address := current_setting('request.headers', true)::json->>'x-forwarded-for';\r\n    v_user_agent := current_setting('request.headers', true)::json->>'user-agent';\r\n  EXCEPTION\r\n    WHEN OTHERS THEN\r\n      v_ip_address := NULL;\r\n      v_user_agent := NULL;\r\n  END;\r\n  \r\n  -- Inserir log\r\n  INSERT INTO public.system_logs (\r\n    user_id,\r\n    user_email,\r\n    user_role,\r\n    action,\r\n    entity_type,\r\n    entity_id,\r\n    old_data,\r\n    new_data,\r\n    ip_address,\r\n    user_agent,\r\n    details\r\n  ) VALUES (\r\n    auth.uid(),\r\n    v_user_email,\r\n    v_user_role,\r\n    p_action,\r\n    p_entity_type,\r\n    p_entity_id,\r\n    p_old_data,\r\n    p_new_data,\r\n    v_ip_address,\r\n    v_user_agent,\r\n    p_details\r\n  )\r\n  RETURNING id INTO v_log_id;\r\n  \r\n  RETURN v_log_id;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.search_system_logs(p_user_id uuid DEFAULT NULL::uuid, p_action text DEFAULT NULL::text, p_entity_type text DEFAULT NULL::text, p_start_date timestamp with time zone DEFAULT NULL::timestamp with time zone, p_end_date timestamp with time zone DEFAULT NULL::timestamp with time zone, p_limit integer DEFAULT 100, p_offset integer DEFAULT 0)\n RETURNS TABLE(id uuid, user_email text, user_role text, action text, entity_type text, entity_id text, ip_address text, created_at timestamp with time zone, total_count bigint)\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nBEGIN\r\n  -- Verificar permissão\r\n  IF NOT EXISTS (\r\n    SELECT 1 FROM public.profiles \r\n    WHERE id = auth.uid() \r\n    AND role IN ('admin', 'manager')\r\n  ) THEN\r\n    -- Usuário comum só vê seus próprios logs\r\n    p_user_id := auth.uid();\r\n  END IF;\r\n  \r\n  RETURN QUERY\r\n  WITH filtered_logs AS (\r\n    SELECT \r\n      sl.id,\r\n      sl.user_email,\r\n      sl.user_role,\r\n      sl.action,\r\n      sl.entity_type,\r\n      sl.entity_id,\r\n      sl.ip_address,\r\n      sl.created_at,\r\n      COUNT(*) OVER() as total_count\r\n    FROM public.system_logs sl\r\n    WHERE (p_user_id IS NULL OR sl.user_id = p_user_id)\r\n      AND (p_action IS NULL OR sl.action = p_action)\r\n      AND (p_entity_type IS NULL OR sl.entity_type = p_entity_type)\r\n      AND (p_start_date IS NULL OR sl.created_at >= p_start_date)\r\n      AND (p_end_date IS NULL OR sl.created_at <= p_end_date)\r\n      -- Gerentes não veem ações de admin\r\n      AND (\r\n        NOT EXISTS (\r\n          SELECT 1 FROM public.profiles \r\n          WHERE id = auth.uid() \r\n          AND role = 'manager'\r\n        )\r\n        OR sl.user_role != 'admin'\r\n      )\r\n    ORDER BY sl.created_at DESC\r\n    LIMIT p_limit\r\n    OFFSET p_offset\r\n  )\r\n  SELECT * FROM filtered_logs;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.get_permissions_by_module()\n RETURNS TABLE(module character varying, permissions jsonb)\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nBEGIN\r\n  RETURN QUERY\r\n  SELECT \r\n    p.module,\r\n    jsonb_agg(\r\n      jsonb_build_object(\r\n        'id', p.id,\r\n        'name', p.name,\r\n        'description', p.description\r\n      ) ORDER BY p.name\r\n    ) as permissions\r\n  FROM public.permissions p\r\n  WHERE p.module IS NOT NULL\r\n  GROUP BY p.module\r\n  ORDER BY p.module;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.get_my_permissions()\n RETURNS TABLE(permission_name character varying, module character varying, description text)\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nBEGIN\r\n  -- Admin tem todas as permissões\r\n  IF EXISTS (\r\n    SELECT 1 FROM public.profiles \r\n    WHERE id = auth.uid() \r\n    AND role = 'admin'\r\n  ) THEN\r\n    RETURN QUERY\r\n    SELECT p.name, p.module, p.description\r\n    FROM public.permissions p\r\n    ORDER BY p.module, p.name;\r\n  ELSE\r\n    -- Retornar apenas permissões atribuídas ao usuário\r\n    RETURN QUERY\r\n    SELECT DISTINCT p.name, p.module, p.description\r\n    FROM public.permissions p\r\n    JOIN public.role_permissions rp ON rp.permission_id = p.id\r\n    JOIN public.user_roles ur ON ur.role_id = rp.role_id\r\n    WHERE ur.user_id = auth.uid()\r\n    ORDER BY p.module, p.name;\r\n  END IF;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.has_permission(p_permission_name text)\n RETURNS boolean\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_has_permission boolean;\r\n  v_user_role text;\r\nBEGIN\r\n  -- Verificar se usuário está autenticado\r\n  IF auth.uid() IS NULL THEN\r\n    RETURN false;\r\n  END IF;\r\n  \r\n  -- Buscar role do usuário\r\n  SELECT role INTO v_user_role\r\n  FROM public.profiles \r\n  WHERE id = auth.uid();\r\n  \r\n  -- Admin tem todas as permissões\r\n  IF v_user_role = 'admin' THEN\r\n    RETURN true;\r\n  END IF;\r\n  \r\n  -- Manager tem permissões específicas (ajuste conforme necessário)\r\n  IF v_user_role = 'manager' THEN\r\n    -- Manager pode fazer quase tudo, exceto algumas ações críticas\r\n    IF p_permission_name IN ('users.delete', 'settings.system', 'admin.full_access') THEN\r\n      RETURN false;\r\n    END IF;\r\n    RETURN true;\r\n  END IF;\r\n  \r\n  -- Verificar permissão específica via role_permissions (se existir tabela)\r\n  IF EXISTS (\r\n    SELECT 1 FROM information_schema.tables \r\n    WHERE table_schema = 'public' \r\n    AND table_name = 'role_permissions'\r\n  ) THEN\r\n    SELECT EXISTS (\r\n      SELECT 1 \r\n      FROM public.role_permissions rp\r\n      JOIN public.permissions p ON p.id = rp.permission_id\r\n      JOIN public.user_roles ur ON ur.role_id = rp.role_id\r\n      WHERE ur.user_id = auth.uid()\r\n        AND p.name = p_permission_name\r\n    ) INTO v_has_permission;\r\n    \r\n    RETURN COALESCE(v_has_permission, false);\r\n  END IF;\r\n  \r\n  -- Fallback: baseado apenas na role\r\n  RETURN false;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.get_logs_statistics(p_start_date timestamp with time zone DEFAULT (now() - '7 days'::interval), p_end_date timestamp with time zone DEFAULT now())\n RETURNS jsonb\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_result jsonb;\r\nBEGIN\r\n  -- Verificar permissão\r\n  IF NOT EXISTS (\r\n    SELECT 1 FROM public.profiles \r\n    WHERE id = auth.uid() \r\n    AND role IN ('admin', 'manager')\r\n  ) THEN\r\n    RAISE EXCEPTION 'Permissão negada';\r\n  END IF;\r\n  \r\n  SELECT jsonb_build_object(\r\n    'total_logs', COUNT(*),\r\n    'by_action', (\r\n      SELECT jsonb_object_agg(action, COUNT(*))\r\n      FROM public.system_logs\r\n      WHERE created_at BETWEEN p_start_date AND p_end_date\r\n      GROUP BY action\r\n    ),\r\n    'by_entity', (\r\n      SELECT jsonb_object_agg(entity_type, COUNT(*))\r\n      FROM public.system_logs\r\n      WHERE created_at BETWEEN p_start_date AND p_end_date\r\n        AND entity_type IS NOT NULL\r\n      GROUP BY entity_type\r\n    ),\r\n    'by_user_role', (\r\n      SELECT jsonb_object_agg(user_role, COUNT(*))\r\n      FROM public.system_logs\r\n      WHERE created_at BETWEEN p_start_date AND p_end_date\r\n      GROUP BY user_role\r\n    ),\r\n    'top_users', (\r\n      SELECT jsonb_agg(\r\n        jsonb_build_object(\r\n          'user_email', user_email,\r\n          'total_actions', COUNT(*)\r\n        )\r\n      )\r\n      FROM public.system_logs\r\n      WHERE created_at BETWEEN p_start_date AND p_end_date\r\n      GROUP BY user_email\r\n      ORDER BY COUNT(*) DESC\r\n      LIMIT 10\r\n    ),\r\n    'daily_activity', (\r\n      SELECT jsonb_object_agg(\r\n        DATE(created_at)::text, \r\n        COUNT(*)\r\n      )\r\n      FROM public.system_logs\r\n      WHERE created_at BETWEEN p_start_date AND p_end_date\r\n      GROUP BY DATE(created_at)\r\n      ORDER BY DATE(created_at)\r\n    )\r\n  ) INTO v_result\r\n  FROM public.system_logs\r\n  WHERE created_at BETWEEN p_start_date AND p_end_date;\r\n  \r\n  RETURN v_result;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.cleanup_old_logs(p_days integer DEFAULT 90)\n RETURNS integer\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_count integer;\r\nBEGIN\r\n  -- Verificar permissão\r\n  IF NOT EXISTS (\r\n    SELECT 1 FROM public.profiles \r\n    WHERE id = auth.uid() \r\n    AND role = 'admin'\r\n  ) THEN\r\n    RAISE EXCEPTION 'Apenas administradores podem limpar logs';\r\n  END IF;\r\n  \r\n  -- Deletar logs antigos\r\n  WITH deleted AS (\r\n    DELETE FROM public.system_logs\r\n    WHERE created_at < (now() - (p_days || ' days')::interval)\r\n    RETURNING id\r\n  )\r\n  SELECT COUNT(*) INTO v_count FROM deleted;\r\n  \r\n  -- Registrar a limpeza\r\n  PERFORM public.log_system_event(\r\n    'cleanup_logs',\r\n    'system_logs',\r\n    NULL,\r\n    jsonb_build_object('days', p_days),\r\n    jsonb_build_object('deleted_count', v_count),\r\n    jsonb_build_object('performed_by', auth.uid())\r\n  );\r\n  \r\n  RETURN v_count;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.log_table_changes()\n RETURNS trigger\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_action text;\r\n  v_old_data jsonb;\r\n  v_new_data jsonb;\r\nBEGIN\r\n  -- Determinar ação\r\n  IF TG_OP = 'INSERT' THEN\r\n    v_action := 'create';\r\n    v_new_data := to_jsonb(NEW);\r\n  ELSIF TG_OP = 'UPDATE' THEN\r\n    v_action := 'update';\r\n    v_old_data := to_jsonb(OLD);\r\n    v_new_data := to_jsonb(NEW);\r\n  ELSIF TG_OP = 'DELETE' THEN\r\n    v_action := 'delete';\r\n    v_old_data := to_jsonb(OLD);\r\n  END IF;\r\n  \r\n  -- Registrar log\r\n  PERFORM public.log_system_event(\r\n    v_action,\r\n    TG_TABLE_NAME,\r\n    CASE \r\n      WHEN TG_OP = 'DELETE' THEN OLD.id::text\r\n      ELSE NEW.id::text\r\n    END,\r\n    v_old_data,\r\n    v_new_data,\r\n    jsonb_build_object('trigger', TG_NAME, 'operation', TG_OP)\r\n  );\r\n  \r\n  RETURN COALESCE(NEW, OLD);\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.soft_delete_coupon(coupon_id bigint)\n RETURNS void\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nBEGIN\r\n  -- Verificar se usuário é admin\r\n  IF NOT EXISTS (\r\n    SELECT 1 FROM public.profiles \r\n    WHERE id = auth.uid() \r\n    AND role = 'admin'\r\n  ) THEN\r\n    RAISE EXCEPTION 'Apenas administradores podem deletar cupons';\r\n  END IF;\r\n  \r\n  -- Soft delete\r\n  UPDATE public.coupons \r\n  SET \r\n    deleted_at = now(),\r\n    deleted_by = auth.uid(),\r\n    is_active = false\r\n  WHERE id = coupon_id \r\n  AND deleted_at IS NULL;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.add_sale_item(p_sale_id bigint, p_product_id bigint, p_quantity numeric, p_unit_price numeric DEFAULT NULL::numeric)\n RETURNS bigint\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_product record;\r\n  v_sale record;\r\n  v_item_id bigint;\r\n  v_actual_price numeric;\r\nBEGIN\r\n  -- Verificar se a venda existe e está pendente\r\n  SELECT * INTO v_sale\r\n  FROM public.sales s\r\n  WHERE s.id = p_sale_id\r\n    AND s.status IN ('pending', 'open');\r\n  \r\n  IF NOT FOUND THEN\r\n    RAISE EXCEPTION 'Venda não encontrada ou já finalizada';\r\n  END IF;\r\n  \r\n  -- Verificar se usuário pode editar esta venda\r\n  IF v_sale.created_by != auth.uid() \r\n     AND NOT EXISTS (\r\n       SELECT 1 FROM public.profiles \r\n       WHERE id = auth.uid() \r\n       AND role IN ('admin', 'manager')\r\n     ) THEN\r\n    RAISE EXCEPTION 'Você não tem permissão para editar esta venda';\r\n  END IF;\r\n  \r\n  -- Buscar produto\r\n  SELECT * INTO v_product\r\n  FROM public.products p\r\n  WHERE p.id = p_product_id\r\n    AND p.is_active = true\r\n    AND p.deleted_at IS NULL;\r\n  \r\n  IF NOT FOUND THEN\r\n    RAISE EXCEPTION 'Produto não encontrado ou inativo';\r\n  END IF;\r\n  \r\n  -- Verificar estoque\r\n  IF v_product.stock_quantity < p_quantity THEN\r\n    RAISE EXCEPTION 'Estoque insuficiente. Disponível: %', v_product.stock_quantity;\r\n  END IF;\r\n  \r\n  -- Definir preço\r\n  v_actual_price := COALESCE(p_unit_price, v_product.price);\r\n  \r\n  -- Verificar se item já existe na venda (atualizar quantidade)\r\n  SELECT id INTO v_item_id\r\n  FROM public.sale_items\r\n  WHERE sale_id = p_sale_id\r\n    AND product_id = p_product_id\r\n    AND unit_price = v_actual_price;\r\n  \r\n  IF FOUND THEN\r\n    -- Atualizar quantidade do item existente\r\n    UPDATE public.sale_items\r\n    SET \r\n      quantity = quantity + p_quantity,\r\n      total_price = (quantity + p_quantity) * unit_price\r\n    WHERE id = v_item_id\r\n    RETURNING id INTO v_item_id;\r\n  ELSE\r\n    -- Inserir novo item\r\n    INSERT INTO public.sale_items (\r\n      sale_id,\r\n      product_id,\r\n      product_name,\r\n      product_code,\r\n      quantity,\r\n      unit_price,\r\n      total_price\r\n    ) VALUES (\r\n      p_sale_id,\r\n      p_product_id,\r\n      v_product.name,\r\n      v_product.code,\r\n      p_quantity,\r\n      v_actual_price,\r\n      p_quantity * v_actual_price\r\n    )\r\n    RETURNING id INTO v_item_id;\r\n  END IF;\r\n  \r\n  RETURN v_item_id;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.update_budget_updated_at()\n RETURNS trigger\n LANGUAGE plpgsql\nAS $function$\r\nBEGIN\r\n  NEW.updated_at = NOW();\r\n  RETURN NEW;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.create_stock_count_session(p_name character varying, p_responsible character varying, p_description text DEFAULT NULL::text, p_location character varying DEFAULT NULL::character varying)\n RETURNS uuid\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_session_id uuid;\r\nBEGIN\r\n  -- Verificar permissão\r\n  IF NOT EXISTS (\r\n    SELECT 1 FROM public.profiles \r\n    WHERE id = auth.uid() \r\n    AND role IN ('admin', 'manager')\r\n  ) AND NOT public.has_permission('inventory.adjust') THEN\r\n    RAISE EXCEPTION 'Permissão negada para criar sessão de contagem';\r\n  END IF;\r\n  \r\n  -- Criar sessão\r\n  INSERT INTO public.stock_count_sessions (\r\n    name,\r\n    description,\r\n    location,\r\n    responsible,\r\n    status,\r\n    created_by,\r\n    started_at\r\n  ) VALUES (\r\n    p_name,\r\n    p_description,\r\n    p_location,\r\n    p_responsible,\r\n    'in_progress',\r\n    auth.uid(),\r\n    now()\r\n  )\r\n  RETURNING id INTO v_session_id;\r\n  \r\n  RETURN v_session_id;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.complete_stock_count_session(p_session_id uuid, p_apply_adjustments boolean DEFAULT false)\n RETURNS void\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_session record;\r\n  v_item record;\r\n  v_adjustments jsonb := '[]'::jsonb;\r\nBEGIN\r\n  -- Buscar sessão\r\n  SELECT * INTO v_session\r\n  FROM public.stock_count_sessions\r\n  WHERE id = p_session_id\r\n    AND status = 'in_progress';\r\n  \r\n  IF NOT FOUND THEN\r\n    RAISE EXCEPTION 'Sessão não encontrada ou não está em andamento';\r\n  END IF;\r\n  \r\n  -- Verificar permissão\r\n  IF v_session.created_by != auth.uid() \r\n     AND NOT EXISTS (\r\n       SELECT 1 FROM public.profiles \r\n       WHERE id = auth.uid() \r\n       AND role IN ('admin', 'manager')\r\n     ) THEN\r\n    RAISE EXCEPTION 'Você não tem permissão para finalizar esta sessão';\r\n  END IF;\r\n  \r\n  -- Verificar se todos os itens foram contados\r\n  IF EXISTS (\r\n    SELECT 1 FROM public.stock_count_items\r\n    WHERE count_session_id = p_session_id\r\n      AND status NOT IN ('counted', 'skipped')\r\n  ) THEN\r\n    RAISE EXCEPTION 'Existem itens pendentes de contagem';\r\n  END IF;\r\n  \r\n  -- Se aplicar ajustes, atualizar estoque\r\n  IF p_apply_adjustments THEN\r\n    FOR v_item IN \r\n      SELECT * FROM public.stock_count_items\r\n      WHERE count_session_id = p_session_id\r\n        AND status = 'counted'\r\n        AND difference != 0\r\n    LOOP\r\n      -- Atualizar estoque do produto\r\n      UPDATE public.products\r\n      SET \r\n        stock_quantity = v_item.counted_quantity,\r\n        updated_at = now(),\r\n        updated_by = auth.uid()\r\n      WHERE id = v_item.product_id;\r\n      \r\n      -- Registrar ajuste\r\n      v_adjustments := v_adjustments || jsonb_build_object(\r\n        'product_id', v_item.product_id,\r\n        'old_quantity', v_item.system_quantity,\r\n        'new_quantity', v_item.counted_quantity,\r\n        'difference', v_item.difference,\r\n        'adjusted_at', now()\r\n      );\r\n    END LOOP;\r\n  END IF;\r\n  \r\n  -- Atualizar estatísticas\r\n  WITH stats AS (\r\n    SELECT \r\n      COUNT(*) as total_items,\r\n      COUNT(*) FILTER (WHERE status = 'counted') as counted_items,\r\n      COUNT(*) FILTER (WHERE difference != 0) as diverged_items\r\n    FROM public.stock_count_items\r\n    WHERE count_session_id = p_session_id\r\n  )\r\n  UPDATE public.stock_count_sessions\r\n  SET \r\n    status = 'completed',\r\n    completed_at = now(),\r\n    completed_by = auth.uid(),\r\n    total_items = stats.total_items,\r\n    counted_items = stats.counted_items,\r\n    diverged_items = stats.diverged_items,\r\n    adjustments = v_adjustments,\r\n    updated_at = now()\r\n  FROM stats\r\n  WHERE id = p_session_id;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.cancel_stock_count_session(p_session_id uuid)\n RETURNS void\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nBEGIN\r\n  -- Verificar permissão\r\n  IF NOT EXISTS (\r\n    SELECT 1 FROM public.profiles \r\n    WHERE id = auth.uid() \r\n    AND role IN ('admin', 'manager')\r\n  ) THEN\r\n    RAISE EXCEPTION 'Apenas administradores podem cancelar sessões';\r\n  END IF;\r\n  \r\n  -- Cancelar sessão\r\n  UPDATE public.stock_count_sessions\r\n  SET \r\n    status = 'cancelled',\r\n    cancelled_at = now(),\r\n    cancelled_by = auth.uid(),\r\n    updated_at = now()\r\n  WHERE id = p_session_id\r\n    AND status = 'in_progress';\r\n    \r\n  IF NOT FOUND THEN\r\n    RAISE EXCEPTION 'Sessão não encontrada ou não está em andamento';\r\n  END IF;\r\n  \r\n  -- Cancelar itens pendentes\r\n  UPDATE public.stock_count_items\r\n  SET \r\n    status = 'skipped',\r\n    notes = COALESCE(notes, '') || ' [Sessão cancelada]',\r\n    updated_at = now()\r\n  WHERE count_session_id = p_session_id\r\n    AND status IN ('pending', 'in_progress');\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.rls_auto_enable()\n RETURNS event_trigger\n LANGUAGE plpgsql\n SECURITY DEFINER\n SET search_path TO 'pg_catalog'\nAS $function$\nDECLARE\n  cmd record;\nBEGIN\n  FOR cmd IN\n    SELECT *\n    FROM pg_event_trigger_ddl_commands()\n    WHERE command_tag IN ('CREATE TABLE', 'CREATE TABLE AS', 'SELECT INTO')\n      AND object_type IN ('table','partitioned table')\n  LOOP\n     IF cmd.schema_name IS NOT NULL AND cmd.schema_name IN ('public') AND cmd.schema_name NOT IN ('pg_catalog','information_schema') AND cmd.schema_name NOT LIKE 'pg_toast%' AND cmd.schema_name NOT LIKE 'pg_temp%' THEN\n      BEGIN\n        EXECUTE format('alter table if exists %s enable row level security', cmd.object_identity);\n        RAISE LOG 'rls_auto_enable: enabled RLS on %', cmd.object_identity;\n      EXCEPTION\n        WHEN OTHERS THEN\n          RAISE LOG 'rls_auto_enable: failed to enable RLS on %', cmd.object_identity;\n      END;\n     ELSE\n        RAISE LOG 'rls_auto_enable: skip % (either system schema or not in enforced list: %.)', cmd.object_identity, cmd.schema_name;\n     END IF;\n  END LOOP;\nEND;\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.register_product_entry(p_product_id bigint, p_invoice_number character varying, p_quantity numeric, p_unit_cost numeric, p_supplier_name character varying DEFAULT NULL::character varying, p_supplier_cnpj character varying DEFAULT NULL::character varying, p_batch_number character varying DEFAULT NULL::character varying, p_manufacture_date date DEFAULT NULL::date, p_expiration_date date DEFAULT NULL::date, p_invoice_series character varying DEFAULT NULL::character varying, p_notes text DEFAULT NULL::text)\n RETURNS bigint\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_entry_id bigint;\r\n  v_product_exists boolean;\r\n  v_total_cost numeric;\r\nBEGIN\r\n  -- Verificar permissão\r\n  IF NOT EXISTS (\r\n    SELECT 1 FROM public.profiles \r\n    WHERE id = auth.uid() \r\n    AND role IN ('admin', 'manager')\r\n  ) AND NOT public.has_permission('products.manage_stock') THEN\r\n    RAISE EXCEPTION 'Permissão negada para registrar entrada de produto';\r\n  END IF;\r\n  \r\n  -- Verificar se produto existe\r\n  SELECT EXISTS (\r\n    SELECT 1 FROM public.products WHERE id = p_product_id\r\n  ) INTO v_product_exists;\r\n  \r\n  IF NOT v_product_exists THEN\r\n    RAISE EXCEPTION 'Produto não encontrado';\r\n  END IF;\r\n  \r\n  -- Validar quantidade\r\n  IF p_quantity <= 0 THEN\r\n    RAISE EXCEPTION 'Quantidade deve ser maior que zero';\r\n  END IF;\r\n  \r\n  -- Validar custo\r\n  IF p_unit_cost < 0 THEN\r\n    RAISE EXCEPTION 'Custo unitário não pode ser negativo';\r\n  END IF;\r\n  \r\n  -- Calcular custo total\r\n  v_total_cost := p_quantity * p_unit_cost;\r\n  \r\n  -- Inserir entrada\r\n  INSERT INTO public.product_entries (\r\n    product_id,\r\n    invoice_number,\r\n    invoice_series,\r\n    supplier_name,\r\n    supplier_cnpj,\r\n    batch_number,\r\n    manufacture_date,\r\n    expiration_date,\r\n    quantity,\r\n    unit_cost,\r\n    total_cost,\r\n    entry_date,\r\n    notes,\r\n    created_by\r\n  ) VALUES (\r\n    p_product_id,\r\n    p_invoice_number,\r\n    p_invoice_series,\r\n    p_supplier_name,\r\n    p_supplier_cnpj,\r\n    p_batch_number,\r\n    p_manufacture_date,\r\n    p_expiration_date,\r\n    p_quantity,\r\n    p_unit_cost,\r\n    v_total_cost,\r\n    CURRENT_DATE,\r\n    p_notes,\r\n    auth.uid()\r\n  )\r\n  RETURNING id INTO v_entry_id;\r\n  \r\n  -- Atualizar estoque do produto (via trigger ou função)\r\n  -- O trigger on_product_entry_insert já deve fazer isso\r\n  \r\n  RETURN v_entry_id;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.register_customer_communication(p_customer_id bigint, p_channel character varying, p_subject text, p_content text, p_status character varying DEFAULT 'sent'::character varying)\n RETURNS uuid\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_communication_id uuid;\r\nBEGIN\r\n  -- Inserir comunicação\r\n  INSERT INTO public.customer_communications (\r\n    customer_id,\r\n    channel,\r\n    subject,\r\n    content,\r\n    status,\r\n    sent_by\r\n  ) VALUES (\r\n    p_customer_id,\r\n    p_channel,\r\n    p_subject,\r\n    p_content,\r\n    p_status,\r\n    auth.uid()\r\n  )\r\n  RETURNING id INTO v_communication_id;\r\n  \r\n  RETURN v_communication_id;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.update_communication_status(p_communication_id uuid, p_status character varying, p_error_message text DEFAULT NULL::text)\n RETURNS void\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nBEGIN\r\n  UPDATE public.customer_communications\r\n  SET \r\n    status = p_status,\r\n    content = CASE \r\n      WHEN p_error_message IS NOT NULL \r\n      THEN content || E'\\n\\n[Erro: ' || p_error_message || ']'\r\n      ELSE content\r\n    END,\r\n    updated_at = now()\r\n  WHERE id = p_communication_id;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.get_product_entries_report(p_start_date date DEFAULT NULL::date, p_end_date date DEFAULT NULL::date, p_product_id bigint DEFAULT NULL::bigint, p_supplier_cnpj character varying DEFAULT NULL::character varying)\n RETURNS TABLE(entry_id bigint, entry_date date, product_id bigint, product_name character varying, invoice_number character varying, supplier_name character varying, supplier_cnpj character varying, quantity numeric, unit_cost numeric, total_cost numeric, batch_number character varying, expiration_date date, created_by_name text, notes text)\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nBEGIN\r\n  -- Verificar permissão\r\n  IF NOT EXISTS (\r\n    SELECT 1 FROM public.profiles \r\n    WHERE id = auth.uid() \r\n    AND role IN ('admin', 'manager')\r\n  ) AND NOT public.has_permission('reports.products') THEN\r\n    RAISE EXCEPTION 'Permissão negada para gerar relatório';\r\n  END IF;\r\n  \r\n  RETURN QUERY\r\n  SELECT \r\n    pe.id,\r\n    pe.entry_date,\r\n    pe.product_id,\r\n    p.name,\r\n    pe.invoice_number,\r\n    pe.supplier_name,\r\n    pe.supplier_cnpj,\r\n    pe.quantity,\r\n    pe.unit_cost,\r\n    pe.total_cost,\r\n    pe.batch_number,\r\n    pe.expiration_date,\r\n    pf.full_name,\r\n    pe.notes\r\n  FROM public.product_entries pe\r\n  JOIN public.products p ON p.id = pe.product_id\r\n  LEFT JOIN public.profiles pf ON pf.id = pe.created_by\r\n  WHERE (p_start_date IS NULL OR pe.entry_date >= p_start_date)\r\n    AND (p_end_date IS NULL OR pe.entry_date <= p_end_date)\r\n    AND (p_product_id IS NULL OR pe.product_id = p_product_id)\r\n    AND (p_supplier_cnpj IS NULL OR pe.supplier_cnpj = p_supplier_cnpj)\r\n  ORDER BY pe.entry_date DESC, pe.id DESC;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.get_product_average_cost(p_product_id bigint)\n RETURNS numeric\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_avg_cost numeric;\r\nBEGIN\r\n  SELECT \r\n    CASE \r\n      WHEN SUM(quantity) > 0 \r\n      THEN SUM(total_cost) / SUM(quantity)\r\n      ELSE 0\r\n    END INTO v_avg_cost\r\n  FROM public.product_entries\r\n  WHERE product_id = p_product_id\r\n    AND entry_date >= (CURRENT_DATE - interval '90 days'); -- Últimos 90 dias\r\n  \r\n  RETURN COALESCE(v_avg_cost, 0);\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.validate_entry_dates()\n RETURNS trigger\n LANGUAGE plpgsql\nAS $function$\r\nBEGIN\r\n  -- Validar data de fabricação vs validade\r\n  IF NEW.manufacture_date IS NOT NULL \r\n     AND NEW.expiration_date IS NOT NULL \r\n     AND NEW.manufacture_date > NEW.expiration_date THEN\r\n    RAISE EXCEPTION 'Data de fabricação não pode ser posterior à data de validade';\r\n  END IF;\r\n  \r\n  -- Validar data de entrada\r\n  IF NEW.entry_date > CURRENT_DATE THEN\r\n    RAISE EXCEPTION 'Data de entrada não pode ser futura';\r\n  END IF;\r\n  \r\n  RETURN NEW;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.clean_old_logs(days_to_keep integer DEFAULT 90)\n RETURNS integer\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n    deleted_count INTEGER;\r\nBEGIN\r\n    DELETE FROM public.system_logs \r\n    WHERE created_at < NOW() - (days_to_keep || ' days')::INTERVAL;\r\n    \r\n    GET DIAGNOSTICS deleted_count = ROW_COUNT;\r\n    \r\n    DELETE FROM public.access_logs \r\n    WHERE created_at < NOW() - (days_to_keep || ' days')::INTERVAL;\r\n    \r\n    RETURN deleted_count;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.update_updated_at_column()\n RETURNS trigger\n LANGUAGE plpgsql\nAS $function$\r\nBEGIN\r\n  NEW.updated_at = NOW();\r\n  RETURN NEW;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.update_stock_on_entry()\n RETURNS trigger\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n    current_stock DECIMAL(10,2);\r\n    new_stock DECIMAL(10,2);\r\nBEGIN\r\n    -- Obter estoque atual\r\n    SELECT COALESCE(stock_quantity, 0) INTO current_stock\r\n    FROM products \r\n    WHERE id = NEW.product_id;\r\n    \r\n    -- Calcular novo estoque\r\n    new_stock := current_stock + NEW.quantity;\r\n    \r\n    -- Atualizar estoque do produto\r\n    UPDATE products \r\n    SET \r\n        stock_quantity = new_stock,\r\n        cost_price = NEW.unit_cost,\r\n        updated_at = NOW(),\r\n        updated_by = NEW.created_by\r\n    WHERE id = NEW.product_id;\r\n    \r\n    -- Registrar movimentação (COM reference_id UUID gerado)\r\n    INSERT INTO stock_movements (\r\n        product_id, \r\n        movement_type, \r\n        quantity, \r\n        quantity_before, \r\n        quantity_after, \r\n        reference_id,\r\n        reference_type, \r\n        created_by,\r\n        created_at,\r\n        reason\r\n    ) VALUES (\r\n        NEW.product_id,\r\n        'ENTRY',\r\n        NEW.quantity,\r\n        current_stock,\r\n        new_stock,\r\n        gen_random_uuid(),\r\n        'product_entry',\r\n        NEW.created_by,\r\n        NOW(),\r\n        'Entrada NF: ' || COALESCE(NEW.invoice_number, 'N/A')\r\n    );\r\n    \r\n    RETURN NEW;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.generate_registration_number()\n RETURNS text\n LANGUAGE plpgsql\nAS $function$\r\nDECLARE\r\n  last_number TEXT;\r\n  next_number INT;\r\nBEGIN\r\n  -- Buscar a última matrícula (formato FUNC000001)\r\n  SELECT registration_number \r\n  INTO last_number\r\n  FROM profiles \r\n  WHERE registration_number IS NOT NULL \r\n    AND registration_number LIKE 'FUNC%'\r\n  ORDER BY created_at DESC \r\n  LIMIT 1;\r\n  \r\n  IF last_number IS NULL THEN\r\n    RETURN 'FUNC000001';\r\n  END IF;\r\n  \r\n  -- Extrair o número e incrementar\r\n  next_number := CAST(SUBSTRING(last_number FROM 5) AS INT) + 1;\r\n  \r\n  -- Formatar com 6 dígitos\r\n  RETURN 'FUNC' || LPAD(next_number::TEXT, 6, '0');\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.set_registration_number()\n RETURNS trigger\n LANGUAGE plpgsql\nAS $function$\r\nBEGIN\r\n  -- Só gera se não foi definida manualmente\r\n  IF NEW.registration_number IS NULL THEN\r\n    NEW.registration_number := generate_registration_number();\r\n  END IF;\r\n  RETURN NEW;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.get_count_sessions_history(p_start_date date DEFAULT NULL::date, p_end_date date DEFAULT NULL::date, p_status character varying DEFAULT NULL::character varying)\n RETURNS TABLE(id uuid, name character varying, location character varying, responsible character varying, status character varying, started_at timestamp with time zone, completed_at timestamp with time zone, total_items integer, counted_items integer, diverged_items integer, created_by_name text)\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nBEGIN\r\n  RETURN QUERY\r\n  SELECT \r\n    scs.id,\r\n    scs.name,\r\n    scs.location,\r\n    scs.responsible,\r\n    scs.status,\r\n    scs.started_at,\r\n    scs.completed_at,\r\n    scs.total_items,\r\n    scs.counted_items,\r\n    scs.diverged_items,\r\n    pf.full_name\r\n  FROM public.stock_count_sessions scs\r\n  LEFT JOIN public.profiles pf ON pf.id = scs.created_by\r\n  WHERE (p_start_date IS NULL OR DATE(scs.started_at) >= p_start_date)\r\n    AND (p_end_date IS NULL OR DATE(scs.started_at) <= p_end_date)\r\n    AND (p_status IS NULL OR scs.status = p_status)\r\n  ORDER BY scs.started_at DESC;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.validate_count_session_dates()\n RETURNS trigger\n LANGUAGE plpgsql\nAS $function$\r\nBEGIN\r\n  -- Validar data de conclusão\r\n  IF NEW.completed_at IS NOT NULL AND NEW.completed_at < NEW.started_at THEN\r\n    RAISE EXCEPTION 'Data de conclusão não pode ser anterior à data de início';\r\n  END IF;\r\n  \r\n  -- Validar data de cancelamento\r\n  IF NEW.cancelled_at IS NOT NULL AND NEW.cancelled_at < NEW.started_at THEN\r\n    RAISE EXCEPTION 'Data de cancelamento não pode ser anterior à data de início';\r\n  END IF;\r\n  \r\n  RETURN NEW;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.use_coupon(p_coupon_id bigint, p_customer_id bigint, p_sale_id bigint DEFAULT NULL::bigint)\n RETURNS bigint\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_coupon_record record;\r\n  v_customer_coupon_id bigint;\r\nBEGIN\r\n  -- Bloquear uso se usuário não estiver autenticado\r\n  IF auth.uid() IS NULL THEN\r\n    RAISE EXCEPTION 'Usuário não autenticado';\r\n  END IF;\r\n\r\n  -- Verificar se o cupom existe e é válido\r\n  SELECT * INTO v_coupon_record\r\n  FROM public.coupons c\r\n  WHERE c.id = p_coupon_id\r\n    AND c.deleted_at IS NULL\r\n    AND c.is_active = true\r\n    AND (c.valid_from IS NULL OR c.valid_from <= now())\r\n    AND (c.valid_to IS NULL OR c.valid_to >= now())\r\n    AND (c.usage_limit IS NULL OR c.used_count < c.usage_limit)\r\n  FOR UPDATE; -- Lock para evitar concorrência\r\n  \r\n  IF NOT FOUND THEN\r\n    RAISE EXCEPTION 'Cupom inválido, expirado ou limite de uso atingido';\r\n  END IF;\r\n  \r\n  -- Verificar se o cupom é global ou se o cliente está na lista de permitidos\r\n  IF NOT v_coupon_record.is_global THEN\r\n    IF NOT EXISTS (\r\n      SELECT 1 FROM public.coupon_allowed_customers cac\r\n      WHERE cac.coupon_id = p_coupon_id\r\n        AND cac.customer_id = p_customer_id\r\n    ) THEN\r\n      RAISE EXCEPTION 'Cliente não autorizado a usar este cupom';\r\n    END IF;\r\n  END IF;\r\n  \r\n  -- Verificar se o cliente já usou este cupom (se for uso único)\r\n  -- Descomente se quiser restringir a 1 uso por cliente\r\n  /*\r\n  IF EXISTS (\r\n    SELECT 1 FROM public.customer_coupons cc\r\n    WHERE cc.coupon_id = p_coupon_id\r\n      AND cc.customer_id = p_customer_id\r\n  ) THEN\r\n    RAISE EXCEPTION 'Cliente já utilizou este cupom';\r\n  END IF;\r\n  */\r\n  \r\n  -- Registrar uso do cupom\r\n  INSERT INTO public.customer_coupons (\r\n    coupon_id,\r\n    customer_id,\r\n    sale_id,\r\n    used_at\r\n  ) VALUES (\r\n    p_coupon_id,\r\n    p_customer_id,\r\n    p_sale_id,\r\n    now()\r\n  )\r\n  RETURNING id INTO v_customer_coupon_id;\r\n  \r\n  -- Incrementar contador de uso\r\n  UPDATE public.coupons\r\n  SET used_count = COALESCE(used_count, 0) + 1\r\n  WHERE id = p_coupon_id;\r\n  \r\n  RETURN v_customer_coupon_id;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.can_use_coupon(p_coupon_code text, p_customer_id bigint, p_purchase_amount numeric DEFAULT NULL::numeric)\n RETURNS jsonb\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_coupon record;\r\n  v_result jsonb;\r\nBEGIN\r\n  -- Buscar cupom pelo código\r\n  SELECT * INTO v_coupon\r\n  FROM public.coupons c\r\n  WHERE c.code = upper(p_coupon_code)\r\n    AND c.deleted_at IS NULL\r\n    AND c.is_active = true\r\n    AND (c.valid_from IS NULL OR c.valid_from <= now())\r\n    AND (c.valid_to IS NULL OR c.valid_to >= now())\r\n    AND (c.usage_limit IS NULL OR c.used_count < c.usage_limit);\r\n  \r\n  IF NOT FOUND THEN\r\n    RETURN jsonb_build_object(\r\n      'valid', false,\r\n      'reason', 'Cupom inválido ou expirado'\r\n    );\r\n  END IF;\r\n  \r\n  -- Verificar valor mínimo de compra\r\n  IF p_purchase_amount IS NOT NULL AND v_coupon.min_purchase > p_purchase_amount THEN\r\n    RETURN jsonb_build_object(\r\n      'valid', false,\r\n      'reason', format('Valor mínimo de compra: R$ %s', v_coupon.min_purchase)\r\n    );\r\n  END IF;\r\n  \r\n  -- Verificar se é global ou cliente permitido\r\n  IF NOT v_coupon.is_global THEN\r\n    IF NOT EXISTS (\r\n      SELECT 1 FROM public.coupon_allowed_customers cac\r\n      WHERE cac.coupon_id = v_coupon.id\r\n        AND cac.customer_id = p_customer_id\r\n    ) THEN\r\n      RETURN jsonb_build_object(\r\n        'valid', false,\r\n        'reason', 'Cupom não disponível para este cliente'\r\n      );\r\n    END IF;\r\n  END IF;\r\n  \r\n  -- Calcular desconto\r\n  WITH discount_calc AS (\r\n    SELECT \r\n      CASE \r\n        WHEN v_coupon.discount_type = 'percent' THEN\r\n          LEAST(\r\n            p_purchase_amount * (v_coupon.discount_value / 100),\r\n            COALESCE(v_coupon.max_discount, p_purchase_amount)\r\n          )\r\n        ELSE\r\n          LEAST(v_coupon.discount_value, p_purchase_amount)\r\n      END as discount_amount\r\n  )\r\n  SELECT jsonb_build_object(\r\n    'valid', true,\r\n    'coupon_id', v_coupon.id,\r\n    'code', v_coupon.code,\r\n    'name', v_coupon.name,\r\n    'discount_type', v_coupon.discount_type,\r\n    'discount_value', v_coupon.discount_value,\r\n    'discount_amount', (SELECT discount_amount FROM discount_calc),\r\n    'max_discount', v_coupon.max_discount,\r\n    'min_purchase', v_coupon.min_purchase\r\n  ) INTO v_result;\r\n  \r\n  RETURN v_result;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.cancel_sale(p_sale_id bigint, p_reason text, p_notes text DEFAULT NULL::text)\n RETURNS void\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_sale record;\r\nBEGIN\r\n  -- Verificar permissão\r\n  IF NOT EXISTS (\r\n    SELECT 1 FROM public.profiles \r\n    WHERE id = auth.uid() \r\n    AND role IN ('admin', 'manager')\r\n  ) THEN\r\n    RAISE EXCEPTION 'Apenas administradores ou gerentes podem cancelar vendas';\r\n  END IF;\r\n  \r\n  -- Buscar venda\r\n  SELECT * INTO v_sale\r\n  FROM public.sales\r\n  WHERE id = p_sale_id;\r\n  \r\n  IF NOT FOUND THEN\r\n    RAISE EXCEPTION 'Venda não encontrada';\r\n  END IF;\r\n  \r\n  -- Verificar se já está cancelada\r\n  IF v_sale.status = 'cancelled' THEN\r\n    RAISE EXCEPTION 'Venda já está cancelada';\r\n  END IF;\r\n  \r\n  -- Cancelar venda\r\n  UPDATE public.sales\r\n  SET \r\n    status = 'cancelled',\r\n    payment_status = 'cancelled',\r\n    cancelled_at = now(),\r\n    cancelled_by = auth.uid(),\r\n    cancellation_reason = p_reason,\r\n    cancellation_notes = p_notes,\r\n    updated_at = now()\r\n  WHERE id = p_sale_id;\r\n  \r\n  -- Devolver itens ao estoque (via trigger ou função)\r\n  -- O trigger on_sale_cancel deve fazer isso\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.handle_new_user()\n RETURNS trigger\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nBEGIN\r\n  -- Inserir perfil do novo usuário\r\n  INSERT INTO public.profiles (\r\n    id, \r\n    email, \r\n    full_name, \r\n    role, \r\n    avatar_url,\r\n    created_at, \r\n    updated_at\r\n  )\r\n  VALUES (\r\n    NEW.id,\r\n    NEW.email,\r\n    COALESCE(NEW.raw_user_meta_data->>'full_name', NEW.email),\r\n    COALESCE(NEW.raw_user_meta_data->>'role', 'operador'),\r\n    NEW.raw_user_meta_data->>'avatar_url',\r\n    NOW(),\r\n    NOW()\r\n  );\r\n  \r\n  -- Registrar log de criação\r\n  INSERT INTO public.system_logs (\r\n    user_id,\r\n    user_email,\r\n    user_role,\r\n    action,\r\n    entity_type,\r\n    entity_id,\r\n    new_data,\r\n    details\r\n  )\r\n  VALUES (\r\n    NEW.id,\r\n    NEW.email,\r\n    COALESCE(NEW.raw_user_meta_data->>'role', 'operador'),\r\n    'CREATE',\r\n    'user',\r\n    NEW.id::text,\r\n    jsonb_build_object(\r\n      'email', NEW.email,\r\n      'full_name', COALESCE(NEW.raw_user_meta_data->>'full_name', NEW.email),\r\n      'role', COALESCE(NEW.raw_user_meta_data->>'role', 'operador')\r\n    ),\r\n    jsonb_build_object(\r\n      'source', 'auth_trigger',\r\n      'method', 'signup'\r\n    )\r\n  );\r\n  \r\n  RETURN NEW;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.handle_profile_update()\n RETURNS trigger\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_old_data jsonb;\r\n  v_new_data jsonb;\r\n  v_changes jsonb;\r\nBEGIN\r\n  -- Capturar dados antigos e novos\r\n  v_old_data = to_jsonb(OLD);\r\n  v_new_data = to_jsonb(NEW);\r\n  \r\n  -- Calcular mudanças\r\n  v_changes = jsonb_strip_nulls(\r\n    jsonb_build_object(\r\n      'full_name', CASE WHEN OLD.full_name IS DISTINCT FROM NEW.full_name THEN jsonb_build_object('old', OLD.full_name, 'new', NEW.full_name) ELSE NULL END,\r\n      'role', CASE WHEN OLD.role IS DISTINCT FROM NEW.role THEN jsonb_build_object('old', OLD.role, 'new', NEW.role) ELSE NULL END,\r\n      'avatar_url', CASE WHEN OLD.avatar_url IS DISTINCT FROM NEW.avatar_url THEN jsonb_build_object('old', OLD.avatar_url, 'new', NEW.avatar_url) ELSE NULL END\r\n    )\r\n  );\r\n  \r\n  -- Registrar log de atualização (apenas se houver mudanças)\r\n  IF v_changes IS NOT NULL AND v_changes <> '{}'::jsonb THEN\r\n    INSERT INTO public.system_logs (\r\n      user_id,\r\n      user_email,\r\n      user_role,\r\n      action,\r\n      entity_type,\r\n      entity_id,\r\n      old_data,\r\n      new_data,\r\n      details\r\n    )\r\n    VALUES (\r\n      NEW.id,\r\n      NEW.email,\r\n      NEW.role,\r\n      'UPDATE',\r\n      'user',\r\n      NEW.id::text,\r\n      v_old_data,\r\n      v_new_data,\r\n      jsonb_build_object(\r\n        'changes', v_changes,\r\n        'source', 'profile_update_trigger'\r\n      )\r\n    );\r\n  END IF;\r\n  \r\n  RETURN NEW;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.handle_profile_delete()\n RETURNS trigger\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nBEGIN\r\n  -- Registrar log de exclusão\r\n  INSERT INTO public.system_logs (\r\n    user_id,\r\n    user_email,\r\n    user_role,\r\n    action,\r\n    entity_type,\r\n    entity_id,\r\n    old_data,\r\n    details\r\n  )\r\n  VALUES (\r\n    OLD.id,\r\n    OLD.email,\r\n    OLD.role,\r\n    'DELETE',\r\n    'user',\r\n    OLD.id::text,\r\n    to_jsonb(OLD),\r\n    jsonb_build_object(\r\n      'source', 'profile_delete_trigger',\r\n      'deleted_at', NOW()\r\n    )\r\n  );\r\n  \r\n  RETURN OLD;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.approve_sale(p_sale_id bigint)\n RETURNS void\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_sale record;\r\nBEGIN\r\n  -- Verificar permissão\r\n  IF NOT EXISTS (\r\n    SELECT 1 FROM public.profiles \r\n    WHERE id = auth.uid() \r\n    AND role IN ('admin', 'manager')\r\n  ) THEN\r\n    RAISE EXCEPTION 'Apenas administradores ou gerentes podem aprovar vendas';\r\n  END IF;\r\n  \r\n  -- Buscar venda\r\n  SELECT * INTO v_sale\r\n  FROM public.sales\r\n  WHERE id = p_sale_id;\r\n  \r\n  IF NOT FOUND THEN\r\n    RAISE EXCEPTION 'Venda não encontrada';\r\n  END IF;\r\n  \r\n  -- Verificar status\r\n  IF v_sale.status != 'pending' THEN\r\n    RAISE EXCEPTION 'Apenas vendas pendentes podem ser aprovadas';\r\n  END IF;\r\n  \r\n  -- Aprovar venda\r\n  UPDATE public.sales\r\n  SET \r\n    status = 'completed',\r\n    payment_status = 'paid',\r\n    approved_by = auth.uid(),\r\n    updated_at = now()\r\n  WHERE id = p_sale_id;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.log_access(p_user_id uuid, p_user_email text, p_ip_address text, p_user_agent text, p_details jsonb DEFAULT NULL::jsonb)\n RETURNS uuid\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_log_id UUID;\r\nBEGIN\r\n  INSERT INTO system_logs (\r\n    user_id,\r\n    user_email,\r\n    action,\r\n    entity_type,\r\n    ip_address,\r\n    user_agent,\r\n    details\r\n  )\r\n  VALUES (\r\n    p_user_id,\r\n    p_user_email,\r\n    'ACCESS',\r\n    'access',\r\n    p_ip_address,\r\n    p_user_agent,\r\n    jsonb_build_object(\r\n      'type', 'access_log',\r\n      'details', p_details,\r\n      'timestamp', NOW()\r\n    )\r\n  )\r\n  RETURNING id INTO v_log_id;\r\n  \r\n  RETURN v_log_id;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.log_system_event(p_user_id uuid, p_user_email text, p_user_role text, p_action text, p_entity_type text DEFAULT NULL::text, p_entity_id text DEFAULT NULL::text, p_old_data jsonb DEFAULT NULL::jsonb, p_new_data jsonb DEFAULT NULL::jsonb, p_details jsonb DEFAULT NULL::jsonb)\n RETURNS uuid\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_log_id UUID;\r\n  v_ip_address TEXT;\r\n  v_user_agent TEXT;\r\nBEGIN\r\n  -- Obter IP e User Agent (se disponível)\r\n  v_ip_address := current_setting('request.headers', true)::json->>'x-forwarded-for';\r\n  v_user_agent := current_setting('request.headers', true)::json->>'user-agent';\r\n  \r\n  -- Inserir log\r\n  INSERT INTO public.system_logs (\r\n    user_id,\r\n    user_email,\r\n    user_role,\r\n    action,\r\n    entity_type,\r\n    entity_id,\r\n    old_data,\r\n    new_data,\r\n    ip_address,\r\n    user_agent,\r\n    details,\r\n    created_at\r\n  )\r\n  VALUES (\r\n    p_user_id,\r\n    p_user_email,\r\n    p_user_role,\r\n    UPPER(p_action),\r\n    p_entity_type,\r\n    p_entity_id,\r\n    p_old_data,\r\n    p_new_data,\r\n    v_ip_address,\r\n    v_user_agent,\r\n    COALESCE(p_details, jsonb_build_object('timestamp', NOW())),\r\n    NOW()\r\n  )\r\n  RETURNING id INTO v_log_id;\r\n  \r\n  RETURN v_log_id;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.is_admin()\n RETURNS boolean\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  user_role TEXT;\r\nBEGIN\r\n  -- Buscar role do usuário atual de forma segura\r\n  SELECT role INTO user_role \r\n  FROM profiles \r\n  WHERE id = auth.uid() \r\n  LIMIT 1;\r\n  \r\n  RETURN COALESCE(user_role = 'admin', FALSE);\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.delete_user_completely(user_id uuid)\n RETURNS jsonb\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  result JSONB;\r\nBEGIN\r\n  -- Verificar se o usuário existe\r\n  IF NOT EXISTS (SELECT 1 FROM auth.users WHERE id = user_id) THEN\r\n    RETURN jsonb_build_object('success', false, 'error', 'Usuário não encontrado');\r\n  END IF;\r\n  \r\n  -- Deletar da tabela profiles (o trigger vai logar)\r\n  DELETE FROM public.profiles WHERE id = user_id;\r\n  \r\n  -- Deletar do auth.users\r\n  DELETE FROM auth.users WHERE id = user_id;\r\n  \r\n  -- Registrar no log do sistema\r\n  INSERT INTO public.system_logs (user_id, action, entity_type, entity_id, details)\r\n  VALUES (\r\n    auth.uid(),\r\n    'DELETE_USER_COMPLETE',\r\n    'user',\r\n    user_id::text,\r\n    jsonb_build_object('deleted_user_id', user_id, 'deleted_by', auth.uid())\r\n  );\r\n  \r\n  RETURN jsonb_build_object('success', true);\r\nEXCEPTION WHEN OTHERS THEN\r\n  RETURN jsonb_build_object('success', false, 'error', SQLERRM);\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.update_products_updated_at()\n RETURNS trigger\n LANGUAGE plpgsql\nAS $function$\r\nBEGIN\r\n    NEW.updated_at = NOW();\r\n    RETURN NEW;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.generate_sale_number()\n RETURNS trigger\n LANGUAGE plpgsql\nAS $function$\r\nDECLARE\r\n    date_part VARCHAR(20);\r\n    sequence_num INT;\r\nBEGIN\r\n    date_part := TO_CHAR(NEW.created_at, 'YYYYMMDD');\r\n    \r\n    SELECT COALESCE(MAX(CAST(SPLIT_PART(sale_number, '-', 3) AS INT)), 0) + 1\r\n    INTO sequence_num\r\n    FROM sales\r\n    WHERE sale_number LIKE 'VENDA-' || date_part || '-%';\r\n    \r\n    NEW.sale_number := 'VENDA-' || date_part || '-' || LPAD(sequence_num::TEXT, 4, '0');\r\n    \r\n    RETURN NEW;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.get_user_role()\n RETURNS text\n LANGUAGE plpgsql\n STABLE\nAS $function$\r\nBEGIN\r\n  RETURN auth.jwt() -> 'app_metadata' ->> 'role';\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.update_stock_on_sale()\n RETURNS trigger\n LANGUAGE plpgsql\nAS $function$\r\nDECLARE\r\n  v_created_by UUID;\r\nBEGIN\r\n  -- Buscar o created_by da venda\r\n  SELECT created_by INTO v_created_by\r\n  FROM sales \r\n  WHERE id = NEW.sale_id;\r\n  \r\n  -- Atualizar estoque do produto\r\n  UPDATE products \r\n  SET \r\n    stock_quantity = stock_quantity - NEW.quantity,\r\n    updated_at = NOW()\r\n  WHERE id = NEW.product_id;\r\n  \r\n  -- Registrar movimentação (USANDO sale_id em vez de reference_id)\r\n  INSERT INTO stock_movements (\r\n    product_id, \r\n    movement_type, \r\n    quantity, \r\n    quantity_before, \r\n    quantity_after, \r\n    sale_id,           -- Usar sale_id (bigint)\r\n    reference_type, \r\n    reason,\r\n    created_by\r\n  )\r\n  SELECT \r\n    NEW.product_id, \r\n    'SALE', \r\n    -NEW.quantity,\r\n    p.stock_quantity + NEW.quantity,\r\n    p.stock_quantity,\r\n    NEW.sale_id,       -- bigint compatível!\r\n    'sale',\r\n    'Venda #' || s.sale_number,\r\n    COALESCE(v_created_by, s.created_by)\r\n  FROM products p\r\n  CROSS JOIN sales s\r\n  WHERE p.id = NEW.product_id\r\n    AND s.id = NEW.sale_id;\r\n  \r\n  RETURN NEW;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.cancel_sale(p_sale_number character varying, p_cancelled_by uuid, p_cancellation_reason text, p_cancellation_notes text DEFAULT NULL::text)\n RETURNS jsonb\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_result JSONB;\r\nBEGIN\r\n  UPDATE sales \r\n  SET \r\n    status = 'cancelled',\r\n    cancelled_at = NOW(),\r\n    cancelled_by = p_cancelled_by,\r\n    cancellation_reason = p_cancellation_reason,\r\n    cancellation_notes = p_cancellation_notes,\r\n    updated_at = NOW()\r\n  WHERE sale_number = p_sale_number\r\n  RETURNING jsonb_build_object(\r\n    'sale_number', sale_number,\r\n    'status', status,\r\n    'cancelled_at', cancelled_at\r\n  ) INTO v_result;\r\n  \r\n  RETURN v_result;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.can_manage_stock()\n RETURNS boolean\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nBEGIN\r\n  RETURN EXISTS (\r\n    SELECT 1 FROM public.profiles \r\n    WHERE id = auth.uid() \r\n    AND role IN ('admin', 'manager')\r\n  ) OR public.has_permission('products.manage_stock');\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.can_adjust_prices()\n RETURNS boolean\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nBEGIN\r\n  RETURN EXISTS (\r\n    SELECT 1 FROM public.profiles \r\n    WHERE id = auth.uid() \r\n    AND role IN ('admin', 'manager')\r\n  ) OR public.has_permission('products.adjust_prices');\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.validate_stock_changes()\n RETURNS trigger\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nBEGIN\r\n  -- Verificar se estoque foi alterado\r\n  IF OLD.stock_quantity != NEW.stock_quantity \r\n     OR OLD.reserved_quantity != NEW.reserved_quantity THEN\r\n    -- Verificar permissão\r\n    IF NOT public.can_manage_stock() THEN\r\n      RAISE EXCEPTION 'Permissão negada: apenas usuários autorizados podem alterar estoque';\r\n    END IF;\r\n  END IF;\r\n  \r\n  -- Verificar se preços foram alterados\r\n  IF OLD.price != NEW.price \r\n     OR OLD.cost_price != NEW.cost_price THEN\r\n    -- Verificar permissão\r\n    IF NOT public.can_adjust_prices() THEN\r\n      RAISE EXCEPTION 'Permissão negada: apenas usuários autorizados podem ajustar preços';\r\n    END IF;\r\n  END IF;\r\n  \r\n  RETURN NEW;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.adjust_product_stock(p_product_id bigint, p_quantity numeric, p_reason text DEFAULT NULL::text)\n RETURNS void\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nBEGIN\r\n  -- Verificar permissão\r\n  IF NOT public.can_manage_stock() THEN\r\n    RAISE EXCEPTION 'Permissão negada para ajustar estoque';\r\n  END IF;\r\n  \r\n  -- Atualizar estoque (o trigger de validação também verificará)\r\n  UPDATE public.products\r\n  SET \r\n    stock_quantity = stock_quantity + p_quantity,\r\n    updated_at = now(),\r\n    updated_by = auth.uid()\r\n  WHERE id = p_product_id\r\n    AND deleted_at IS NULL;\r\n  \r\n  IF NOT FOUND THEN\r\n    RAISE EXCEPTION 'Produto não encontrado ou deletado';\r\n  END IF;\r\n  \r\n  -- Registrar no histórico (opcional)\r\n  -- INSERT INTO public.stock_movements ...\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.update_product_price(p_product_id bigint, p_new_price numeric, p_new_cost_price numeric DEFAULT NULL::numeric)\n RETURNS void\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nBEGIN\r\n  -- Verificar permissão\r\n  IF NOT public.can_adjust_prices() THEN\r\n    RAISE EXCEPTION 'Permissão negada para ajustar preços';\r\n  END IF;\r\n  \r\n  -- Validar preço\r\n  IF p_new_price < 0 THEN\r\n    RAISE EXCEPTION 'Preço não pode ser negativo';\r\n  END IF;\r\n  \r\n  -- Atualizar preços (o trigger de validação também verificará)\r\n  UPDATE public.products\r\n  SET \r\n    price = p_new_price,\r\n    cost_price = COALESCE(p_new_cost_price, cost_price),\r\n    updated_at = now(),\r\n    updated_by = auth.uid()\r\n  WHERE id = p_product_id\r\n    AND deleted_at IS NULL;\r\n  \r\n  IF NOT FOUND THEN\r\n    RAISE EXCEPTION 'Produto não encontrado ou deletado';\r\n  END IF;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.update_sale_payment_status(p_sale_id bigint, p_payment_status character varying, p_payment_method character varying DEFAULT NULL::character varying)\n RETURNS void\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nBEGIN\r\n  -- Verificar se venda existe\r\n  IF NOT EXISTS (\r\n    SELECT 1 FROM public.sales\r\n    WHERE id = p_sale_id\r\n      AND status != 'cancelled'\r\n  ) THEN\r\n    RAISE EXCEPTION 'Venda não encontrada ou cancelada';\r\n  END IF;\r\n  \r\n  -- Verificar permissão\r\n  IF NOT EXISTS (\r\n    SELECT 1 FROM public.sales\r\n    WHERE id = p_sale_id\r\n      AND created_by = auth.uid()\r\n  ) AND NOT EXISTS (\r\n    SELECT 1 FROM public.profiles \r\n    WHERE id = auth.uid() \r\n    AND role IN ('admin', 'manager')\r\n  ) THEN\r\n    RAISE EXCEPTION 'Você não tem permissão para alterar esta venda';\r\n  END IF;\r\n  \r\n  -- Atualizar status\r\n  UPDATE public.sales\r\n  SET \r\n    payment_status = p_payment_status,\r\n    payment_method = COALESCE(p_payment_method, payment_method),\r\n    updated_at = now()\r\n  WHERE id = p_sale_id;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.get_daily_sales_summary(p_date date DEFAULT CURRENT_DATE)\n RETURNS jsonb\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_result jsonb;\r\nBEGIN\r\n  SELECT jsonb_build_object(\r\n    'date', p_date,\r\n    'total_sales', COUNT(*),\r\n    'total_amount', COALESCE(SUM(final_amount), 0),\r\n    'avg_ticket', COALESCE(AVG(final_amount), 0),\r\n    'payment_methods', (\r\n      SELECT jsonb_object_agg(payment_method, COUNT(*))\r\n      FROM public.sales\r\n      WHERE DATE(created_at) = p_date\r\n        AND status = 'completed'\r\n      GROUP BY payment_method\r\n    )\r\n  )\r\n  INTO v_result\r\n  FROM public.sales\r\n  WHERE DATE(created_at) = p_date\r\n    AND status = 'completed';\r\n  \r\n  RETURN v_result;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.update_coupons_updated_at()\n RETURNS trigger\n LANGUAGE plpgsql\nAS $function$\r\nBEGIN\r\n  NEW.updated_at = NOW();\r\n  RETURN NEW;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.validate_sale_amounts()\n RETURNS trigger\n LANGUAGE plpgsql\nAS $function$\r\nBEGIN\r\n  -- Validar valores\r\n  IF NEW.total_amount < 0 THEN\r\n    RAISE EXCEPTION 'Valor total não pode ser negativo';\r\n  END IF;\r\n  \r\n  IF NEW.discount_amount < 0 THEN\r\n    RAISE EXCEPTION 'Desconto não pode ser negativo';\r\n  END IF;\r\n  \r\n  IF NEW.final_amount < 0 THEN\r\n    RAISE EXCEPTION 'Valor final não pode ser negativo';\r\n  END IF;\r\n  \r\n  -- Calcular valor final se não informado\r\n  IF NEW.final_amount = 0 AND NEW.total_amount > 0 THEN\r\n    NEW.final_amount := NEW.total_amount - COALESCE(NEW.discount_amount, 0);\r\n  END IF;\r\n  \r\n  RETURN NEW;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.update_profile_login_info()\n RETURNS trigger\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nBEGIN\r\n  -- Atualizar último login e incrementar contador\r\n  UPDATE profiles\r\n  SET \r\n    last_login = NOW(),\r\n    login_count = COALESCE(login_count, 0) + 1,\r\n    updated_at = NOW()\r\n  WHERE id = NEW.id;\r\n  \r\n  RETURN NEW;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.update_user_login_info(user_id uuid)\n RETURNS void\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nBEGIN\r\n  UPDATE profiles\r\n  SET \r\n    last_login = NOW(),\r\n    login_count = COALESCE(login_count, 0) + 1,\r\n    updated_at = NOW()\r\n  WHERE id = user_id;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.handle_auth_user_login()\n RETURNS trigger\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nBEGIN\r\n  -- Atualizar last_login na tabela profiles\r\n  UPDATE profiles\r\n  SET \r\n    last_login = NOW(),\r\n    login_count = COALESCE(login_count, 0) + 1,\r\n    updated_at = NOW()\r\n  WHERE id = NEW.id;\r\n  \r\n  RETURN NEW;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.soft_delete_customer(p_customer_id bigint)\n RETURNS void\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nBEGIN\r\n  -- Verificar se usuário é admin/manager\r\n  IF NOT EXISTS (\r\n    SELECT 1 FROM public.profiles \r\n    WHERE id = auth.uid() \r\n    AND role IN ('admin', 'manager')\r\n  ) THEN\r\n    RAISE EXCEPTION 'Apenas administradores ou gerentes podem deletar clientes';\r\n  END IF;\r\n  \r\n  -- Verificar se cliente existe e não está deletado\r\n  IF NOT EXISTS (\r\n    SELECT 1 FROM public.customers \r\n    WHERE id = p_customer_id \r\n    AND deleted_at IS NULL\r\n  ) THEN\r\n    RAISE EXCEPTION 'Cliente não encontrado ou já deletado';\r\n  END IF;\r\n  \r\n  -- Soft delete\r\n  UPDATE public.customers \r\n  SET \r\n    deleted_at = now(),\r\n    deleted_by = auth.uid(),\r\n    status = 'inactive'\r\n  WHERE id = p_customer_id \r\n  AND deleted_at IS NULL;\r\n  \r\n  -- Opcional: Anonimizar dados sensíveis\r\n  UPDATE public.customers \r\n  SET \r\n    email = 'deleted_' || id || '@deleted.com',\r\n    phone = null,\r\n    document = null,\r\n    address = null\r\n  WHERE id = p_customer_id \r\n  AND deleted_at IS NOT NULL;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.get_customer(p_customer_id bigint)\n RETURNS jsonb\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_customer record;\r\n  v_result jsonb;\r\nBEGIN\r\n  -- Buscar cliente\r\n  SELECT * INTO v_customer\r\n  FROM public.customers c\r\n  WHERE c.id = p_customer_id\r\n    AND c.deleted_at IS NULL;\r\n  \r\n  IF NOT FOUND THEN\r\n    RETURN jsonb_build_object(\r\n      'found', false,\r\n      'message', 'Cliente não encontrado'\r\n    );\r\n  END IF;\r\n  \r\n  -- Verificar permissão (se cliente estiver inativo, só admin/manager vê)\r\n  IF v_customer.status = 'inactive' THEN\r\n    IF NOT EXISTS (\r\n      SELECT 1 FROM public.profiles \r\n      WHERE id = auth.uid() \r\n      AND role IN ('admin', 'manager')\r\n    ) THEN\r\n      RETURN jsonb_build_object(\r\n        'found', false,\r\n        'message', 'Cliente inativo - permissão negada'\r\n      );\r\n    END IF;\r\n  END IF;\r\n  \r\n  -- Retornar dados (ocultar informações sensíveis para operadores)\r\n  SELECT jsonb_build_object(\r\n    'found', true,\r\n    'id', v_customer.id,\r\n    'name', v_customer.name,\r\n    'email', v_customer.email,\r\n    'phone', v_customer.phone,\r\n    'document', CASE \r\n      WHEN EXISTS (\r\n        SELECT 1 FROM public.profiles \r\n        WHERE id = auth.uid() \r\n        AND role IN ('admin', 'manager')\r\n      ) THEN v_customer.document\r\n      ELSE '***' || RIGHT(v_customer.document, 4)\r\n    END,\r\n    'address', v_customer.address,\r\n    'city', v_customer.city,\r\n    'state', v_customer.state,\r\n    'zip_code', v_customer.zip_code,\r\n    'birth_date', v_customer.birth_date,\r\n    'status', v_customer.status,\r\n    'total_purchases', v_customer.total_purchases,\r\n    'last_purchase', v_customer.last_purchase\r\n  ) INTO v_result;\r\n  \r\n  RETURN v_result;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.update_customer_stats(p_customer_id bigint, p_purchase_amount numeric)\n RETURNS void\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nBEGIN\r\n  UPDATE public.customers\r\n  SET \r\n    total_purchases = COALESCE(total_purchases, 0) + p_purchase_amount,\r\n    last_purchase = CURRENT_DATE,\r\n    updated_at = now()\r\n  WHERE id = p_customer_id\r\n    AND deleted_at IS NULL;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.prevent_update_deleted_customer()\n RETURNS trigger\n LANGUAGE plpgsql\nAS $function$\r\nBEGIN\r\n  IF OLD.deleted_at IS NOT NULL THEN\r\n    RAISE EXCEPTION 'Não é possível atualizar cliente deletado';\r\n  END IF;\r\n  RETURN NEW;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.get_system_setting(p_setting_key text, p_default_value text DEFAULT NULL::text)\n RETURNS text\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_value text;\r\nBEGIN\r\n  -- Mapear chave para coluna\r\n  CASE p_setting_key\r\n    WHEN 'currency' THEN\r\n      SELECT currency::text INTO v_value FROM public.system_settings LIMIT 1;\r\n    WHEN 'date_format' THEN\r\n      SELECT date_format INTO v_value FROM public.system_settings LIMIT 1;\r\n    WHEN 'time_format' THEN\r\n      SELECT time_format INTO v_value FROM public.system_settings LIMIT 1;\r\n    WHEN 'language' THEN\r\n      SELECT language INTO v_value FROM public.system_settings LIMIT 1;\r\n    WHEN 'timezone' THEN\r\n      SELECT timezone INTO v_value FROM public.system_settings LIMIT 1;\r\n    ELSE\r\n      v_value := p_default_value;\r\n  END CASE;\r\n  \r\n  RETURN COALESCE(v_value, p_default_value);\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.notify_low_stock()\n RETURNS trigger\n LANGUAGE plpgsql\nAS $function$\r\nBEGIN\r\n  IF NEW.stock_quantity <= NEW.min_stock AND OLD.stock_quantity > OLD.min_stock THEN\r\n    INSERT INTO notifications (user_id, title, message, type, entity_type, entity_id)\r\n    SELECT \r\n      p.id,\r\n      'Estoque Baixo',\r\n      'O produto ' || NEW.name || ' está com estoque baixo (' || NEW.stock_quantity || ' ' || NEW.unit || ')',\r\n      'warning',\r\n      'product',\r\n      NEW.id\r\n    FROM profiles p\r\n    WHERE p.role IN ('admin', 'gerente');\r\n  END IF;\r\n  RETURN NEW;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.get_cashier_summary(p_start_date timestamp with time zone, p_end_date timestamp with time zone, p_user_id uuid DEFAULT NULL::uuid)\n RETURNS jsonb\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_total_vendas DECIMAL(10,2);\r\n  v_total_descontos DECIMAL(10,2);\r\n  v_total_itens BIGINT;\r\n  v_total_clientes BIGINT;\r\n  v_ticket_medio DECIMAL(10,2);\r\n  v_total_cancelamentos DECIMAL(10,2);\r\n  v_total_liquido DECIMAL(10,2);\r\n  v_payment_methods JSONB;\r\n  v_user_sales JSONB;\r\nBEGIN\r\n  -- 1. Resumo geral das vendas\r\n  SELECT \r\n    COALESCE(SUM(CASE WHEN status = 'completed' THEN final_amount ELSE 0 END), 0),\r\n    COALESCE(SUM(discount_amount), 0),\r\n    COUNT(*),\r\n    COUNT(DISTINCT customer_id),\r\n    COALESCE(AVG(CASE WHEN status = 'completed' THEN final_amount ELSE NULL END), 0),\r\n    COALESCE(SUM(CASE WHEN status = 'cancelled' THEN final_amount ELSE 0 END), 0),\r\n    COALESCE(SUM(CASE WHEN status = 'completed' THEN final_amount ELSE 0 END), 0)\r\n  INTO \r\n    v_total_vendas,\r\n    v_total_descontos,\r\n    v_total_itens,\r\n    v_total_clientes,\r\n    v_ticket_medio,\r\n    v_total_cancelamentos,\r\n    v_total_liquido\r\n  FROM sales\r\n  WHERE created_at BETWEEN p_start_date AND p_end_date\r\n    AND (p_user_id IS NULL OR created_by = p_user_id);\r\n  \r\n  -- 2. Vendas por meio de pagamento\r\n  WITH payment_summary AS (\r\n    SELECT \r\n      payment_method,\r\n      COUNT(*) as pm_count,\r\n      SUM(final_amount) as pm_total\r\n    FROM sales\r\n    WHERE created_at BETWEEN p_start_date AND p_end_date\r\n      AND status = 'completed'\r\n      AND (p_user_id IS NULL OR created_by = p_user_id)\r\n    GROUP BY payment_method\r\n  )\r\n  SELECT COALESCE(\r\n    (SELECT jsonb_agg(\r\n      jsonb_build_object(\r\n        'payment_method', payment_method,\r\n        'count', pm_count,\r\n        'total', pm_total\r\n      )\r\n    ) FROM payment_summary),\r\n    '[]'::jsonb\r\n  ) INTO v_payment_methods;\r\n  \r\n  -- 3. Vendas por usuário/operador\r\n  WITH user_summary AS (\r\n    SELECT \r\n      s.created_by,\r\n      COALESCE(p.full_name, p.email, 'Sistema') as usr_name,\r\n      COUNT(*) as usr_vendas,\r\n      SUM(s.final_amount) as usr_valor,\r\n      SUM(s.discount_amount) as usr_descontos,\r\n      AVG(s.final_amount) as usr_ticket\r\n    FROM sales s\r\n    LEFT JOIN profiles p ON p.id = s.created_by\r\n    WHERE s.created_at BETWEEN p_start_date AND p_end_date\r\n      AND s.status = 'completed'\r\n      AND (p_user_id IS NULL OR s.created_by = p_user_id)\r\n    GROUP BY s.created_by, p.full_name, p.email\r\n  )\r\n  SELECT COALESCE(\r\n    (SELECT jsonb_agg(\r\n      jsonb_build_object(\r\n        'user_id', created_by,\r\n        'user_name', usr_name,\r\n        'total_vendas', usr_vendas,\r\n        'total_valor', usr_valor,\r\n        'total_descontos', usr_descontos,\r\n        'media_ticket', usr_ticket\r\n      )\r\n    ) FROM user_summary),\r\n    '[]'::jsonb\r\n  ) INTO v_user_sales;\r\n  \r\n  -- Retornar resultado final\r\n  RETURN jsonb_build_object(\r\n    'resumo', jsonb_build_object(\r\n      'total_vendas', v_total_vendas,\r\n      'total_descontos', v_total_descontos,\r\n      'total_itens', v_total_itens,\r\n      'total_clientes', v_total_clientes,\r\n      'ticket_medio', v_ticket_medio,\r\n      'total_cancelamentos', v_total_cancelamentos,\r\n      'total_liquido', v_total_liquido\r\n    ),\r\n    'meios_pagamento', v_payment_methods,\r\n    'vendas_por_usuario', v_user_sales\r\n  );\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.notify_new_sale()\n RETURNS trigger\n LANGUAGE plpgsql\nAS $function$\r\nBEGIN\r\n  INSERT INTO notifications (user_id, title, message, type, entity_type, entity_id)\r\n  SELECT \r\n    p.id,\r\n    'Nova Venda',\r\n    'Venda #' || NEW.sale_number || ' realizada no valor de R$ ' || NEW.final_amount,\r\n    'success',\r\n    'sale',\r\n    NEW.id\r\n  FROM profiles p\r\n  WHERE p.role IN ('admin', 'gerente');\r\n  \r\n  RETURN NEW;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.notify_coupon_expiring()\n RETURNS trigger\n LANGUAGE plpgsql\nAS $function$\r\nBEGIN\r\n  IF NEW.valid_to IS NOT NULL AND NEW.valid_to - INTERVAL '3 days' <= NOW() THEN\r\n    INSERT INTO notifications (user_id, title, message, type, entity_type, entity_id)\r\n    SELECT \r\n      p.id,\r\n      'Cupom Expirando',\r\n      'O cupom ' || NEW.code || ' expira em ' || TO_CHAR(NEW.valid_to, 'DD/MM/YYYY'),\r\n      'warning',\r\n      'coupon',\r\n      NEW.id\r\n    FROM profiles p\r\n    WHERE p.role IN ('admin', 'gerente');\r\n  END IF;\r\n  RETURN NEW;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.update_customer_last_purchase()\n RETURNS trigger\n LANGUAGE plpgsql\nAS $function$\r\nBEGIN\r\n  IF NEW.customer_id IS NOT NULL AND NEW.status = 'completed' THEN\r\n    UPDATE customers \r\n    SET last_purchase = NEW.created_at,\r\n        updated_at = NOW()\r\n    WHERE id = NEW.customer_id;\r\n  END IF;\r\n  RETURN NEW;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.register_manual_stock_movement(p_product_id bigint, p_quantity numeric, p_reason text)\n RETURNS bigint\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_current_stock numeric;\r\n  v_new_stock numeric;\r\n  v_movement_id bigint;\r\n  v_movement_type character varying(20);\r\nBEGIN\r\n  -- Verificar permissão\r\n  IF NOT EXISTS (\r\n    SELECT 1 FROM public.profiles \r\n    WHERE id = auth.uid() \r\n    AND role IN ('admin', 'manager')\r\n  ) AND NOT public.has_permission('inventory.adjust') THEN\r\n    RAISE EXCEPTION 'Permissão negada para ajustar estoque manualmente';\r\n  END IF;\r\n  \r\n  -- Buscar estoque atual\r\n  SELECT stock_quantity INTO v_current_stock\r\n  FROM public.products\r\n  WHERE id = p_product_id\r\n    AND deleted_at IS NULL;\r\n  \r\n  IF NOT FOUND THEN\r\n    RAISE EXCEPTION 'Produto não encontrado ou deletado';\r\n  END IF;\r\n  \r\n  -- Calcular novo estoque\r\n  v_new_stock := v_current_stock + p_quantity;\r\n  \r\n  -- Validar estoque mínimo\r\n  IF v_new_stock < 0 THEN\r\n    RAISE EXCEPTION 'Estoque insuficiente. Disponível: %, Tentativa: %', v_current_stock, ABS(p_quantity);\r\n  END IF;\r\n  \r\n  -- Definir tipo de movimentação\r\n  v_movement_type := CASE \r\n    WHEN p_quantity > 0 THEN 'manual_in'\r\n    ELSE 'manual_out'\r\n  END;\r\n  \r\n  -- Registrar movimentação\r\n  INSERT INTO public.stock_movements (\r\n    product_id,\r\n    movement_type,\r\n    quantity,\r\n    quantity_before,\r\n    quantity_after,\r\n    reference_type,\r\n    reason,\r\n    created_by\r\n  ) VALUES (\r\n    p_product_id,\r\n    v_movement_type,\r\n    p_quantity,\r\n    v_current_stock,\r\n    v_new_stock,\r\n    'manual',\r\n    p_reason,\r\n    auth.uid()\r\n  )\r\n  RETURNING id INTO v_movement_id;\r\n  \r\n  -- Atualizar estoque do produto\r\n  UPDATE public.products\r\n  SET \r\n    stock_quantity = v_new_stock,\r\n    updated_at = now(),\r\n    updated_by = auth.uid()\r\n  WHERE id = p_product_id;\r\n  \r\n  RETURN v_movement_id;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.get_product_stock_history(p_product_id bigint, p_start_date date DEFAULT NULL::date, p_end_date date DEFAULT NULL::date)\n RETURNS TABLE(id bigint, movement_type character varying, quantity numeric, quantity_before numeric, quantity_after numeric, reference_type character varying, reference_id uuid, reason text, created_at timestamp with time zone, created_by_name text)\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nBEGIN\r\n  RETURN QUERY\r\n  SELECT \r\n    sm.id,\r\n    sm.movement_type,\r\n    sm.quantity,\r\n    sm.quantity_before,\r\n    sm.quantity_after,\r\n    sm.reference_type,\r\n    sm.reference_id,\r\n    sm.reason,\r\n    sm.created_at,\r\n    pf.full_name\r\n  FROM public.stock_movements sm\r\n  LEFT JOIN public.profiles pf ON pf.id = sm.created_by\r\n  WHERE sm.product_id = p_product_id\r\n    AND (p_start_date IS NULL OR DATE(sm.created_at) >= p_start_date)\r\n    AND (p_end_date IS NULL OR DATE(sm.created_at) <= p_end_date)\r\n  ORDER BY sm.created_at DESC;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.cancel_sale_with_approval(p_sale_number character varying, p_cancelled_by uuid, p_approved_by uuid, p_cancellation_reason text, p_cancellation_notes text DEFAULT NULL::text)\n RETURNS jsonb\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_sale_record RECORD;\r\n  v_item RECORD;\r\n  v_previous_stock DECIMAL(10,2);\r\n  v_restored_count INTEGER := 0;\r\n  v_coupon_restored BOOLEAN := false;\r\n  v_customer_updated BOOLEAN := false;\r\nBEGIN\r\n  -- 1. Buscar a venda\r\n  SELECT * INTO v_sale_record\r\n  FROM sales\r\n  WHERE sale_number = p_sale_number;\r\n  \r\n  IF NOT FOUND THEN\r\n    RAISE EXCEPTION 'Venda não encontrada: %', p_sale_number;\r\n  END IF;\r\n  \r\n  -- Verificar se já está cancelada\r\n  IF v_sale_record.status = 'cancelled' THEN\r\n    RAISE EXCEPTION 'Venda já está cancelada';\r\n  END IF;\r\n  \r\n  -- 2. Atualizar status da venda\r\n  UPDATE sales\r\n  SET \r\n    status = 'cancelled',\r\n    cancelled_at = NOW(),\r\n    cancelled_by = p_cancelled_by,\r\n    approved_by = p_approved_by,\r\n    cancellation_reason = p_cancellation_reason,\r\n    cancellation_notes = p_cancellation_notes,\r\n    updated_at = NOW()\r\n  WHERE sale_number = p_sale_number;\r\n  \r\n  -- 3. Restaurar estoque dos produtos\r\n  FOR v_item IN \r\n    SELECT * FROM sale_items WHERE sale_id = v_sale_record.id\r\n  LOOP\r\n    -- Buscar estoque atual\r\n    SELECT COALESCE(stock_quantity, 0) INTO v_previous_stock\r\n    FROM products\r\n    WHERE id = v_item.product_id;\r\n    \r\n    -- Atualizar estoque\r\n    UPDATE products\r\n    SET \r\n      stock_quantity = COALESCE(stock_quantity, 0) + v_item.quantity,\r\n      updated_at = NOW()\r\n    WHERE id = v_item.product_id;\r\n    \r\n    -- Registrar movimentação de estoque\r\n    INSERT INTO stock_movements (\r\n      product_id,\r\n      movement_type,\r\n      quantity,\r\n      quantity_before,\r\n      quantity_after,\r\n      reference_type,\r\n      reason,\r\n      created_by,\r\n      created_at\r\n    ) VALUES (\r\n      v_item.product_id,\r\n      'CANCELLATION',\r\n      v_item.quantity,\r\n      v_previous_stock,\r\n      v_previous_stock + v_item.quantity,\r\n      'sale_cancellation',\r\n      'Cancelamento da venda #' || p_sale_number,\r\n      p_cancelled_by,\r\n      NOW()\r\n    );\r\n    \r\n    v_restored_count := v_restored_count + 1;\r\n  END LOOP;\r\n  \r\n  -- 4. Devolver cupom se existir\r\n  IF v_sale_record.coupon_code IS NOT NULL THEN\r\n    UPDATE coupons\r\n    SET \r\n      used_count = GREATEST(COALESCE(used_count, 0) - 1, 0),\r\n      updated_at = NOW()\r\n    WHERE code = v_sale_record.coupon_code;\r\n    \r\n    v_coupon_restored := true;\r\n  END IF;\r\n  \r\n  -- 5. Atualizar total de compras do cliente\r\n  IF v_sale_record.customer_id IS NOT NULL THEN\r\n    UPDATE customers\r\n    SET \r\n      total_purchases = GREATEST(COALESCE(total_purchases, 0) - v_sale_record.final_amount, 0),\r\n      updated_at = NOW()\r\n    WHERE id = v_sale_record.customer_id;\r\n    \r\n    v_customer_updated := true;\r\n  END IF;\r\n  \r\n  -- 6. Retornar resultado\r\n  RETURN jsonb_build_object(\r\n    'success', true,\r\n    'sale_number', p_sale_number,\r\n    'items_restored', v_restored_count,\r\n    'coupon_restored', v_coupon_restored,\r\n    'customer_updated', v_customer_updated,\r\n    'message', 'Venda cancelada com sucesso'\r\n  );\r\n  \r\nEXCEPTION\r\n  WHEN OTHERS THEN\r\n    RAISE EXCEPTION 'Erro ao cancelar venda: %', SQLERRM;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.is_user_active()\n RETURNS boolean\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nBEGIN\r\n  RETURN EXISTS (\r\n    SELECT 1 FROM profiles \r\n    WHERE id = auth.uid() \r\n      AND status = 'active'\r\n  );\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.block_inactive_user_login()\n RETURNS trigger\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nBEGIN\r\n  IF EXISTS (\r\n    SELECT 1 FROM profiles \r\n    WHERE id = NEW.id AND status != 'active'\r\n  ) THEN\r\n    RAISE EXCEPTION 'Usuário inativo ou bloqueado. Contate o administrador.';\r\n  END IF;\r\n  RETURN NEW;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.soft_delete_instead()\n RETURNS trigger\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nBEGIN\r\n  -- Em vez de deletar, marca como deletado\r\n  UPDATE products \r\n  SET deleted_at = NOW(), deleted_by = auth.uid()\r\n  WHERE id = OLD.id;\r\n  \r\n  -- Impede a exclusão real\r\n  RETURN NULL;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.restore_record(p_table_name text, p_record_id bigint)\n RETURNS jsonb\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_result JSONB;\r\nBEGIN\r\n  -- Apenas admin pode restaurar\r\n  IF NOT EXISTS (\r\n    SELECT 1 FROM profiles \r\n    WHERE id = auth.uid() AND role = 'admin'\r\n  ) THEN\r\n    RAISE EXCEPTION 'Apenas administradores podem restaurar registros';\r\n  END IF;\r\n  \r\n  CASE p_table_name\r\n    WHEN 'products' THEN\r\n      UPDATE products \r\n      SET deleted_at = NULL, deleted_by = NULL, updated_at = NOW()\r\n      WHERE id = p_record_id AND deleted_at IS NOT NULL\r\n      RETURNING to_jsonb(products.*) INTO v_result;\r\n      \r\n    WHEN 'customers' THEN\r\n      UPDATE customers \r\n      SET deleted_at = NULL, deleted_by = NULL, updated_at = NOW()\r\n      WHERE id = p_record_id AND deleted_at IS NOT NULL\r\n      RETURNING to_jsonb(customers.*) INTO v_result;\r\n      \r\n    WHEN 'coupons' THEN\r\n      UPDATE coupons \r\n      SET deleted_at = NULL, deleted_by = NULL, updated_at = NOW()\r\n      WHERE id = p_record_id AND deleted_at IS NOT NULL\r\n      RETURNING to_jsonb(coupons.*) INTO v_result;\r\n      \r\n    ELSE\r\n      RAISE EXCEPTION 'Restauração não suportada para: %', p_table_name;\r\n  END CASE;\r\n  \r\n  -- Log da restauração\r\n  INSERT INTO system_logs (\r\n    user_id, user_email, user_role, action, entity_type, \r\n    entity_id, new_data, details\r\n  ) VALUES (\r\n    auth.uid(), \r\n    (SELECT email FROM profiles WHERE id = auth.uid()),\r\n    (SELECT role FROM profiles WHERE id = auth.uid()),\r\n    'RESTORE',\r\n    p_table_name,\r\n    p_record_id::text,\r\n    v_result,\r\n    jsonb_build_object('restored_at', NOW())\r\n  );\r\n  \r\n  RETURN jsonb_build_object('success', true, 'data', v_result);\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.audit_product_changes()\n RETURNS trigger\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_changes JSONB := '{}'::jsonb;\r\n  v_old_data JSONB;\r\n  v_new_data JSONB;\r\nBEGIN\r\n  IF TG_OP = 'UPDATE' THEN\r\n    -- Comparar cada campo e registrar apenas o que mudou\r\n    IF OLD.name IS DISTINCT FROM NEW.name THEN\r\n      v_changes := v_changes || jsonb_build_object('name', jsonb_build_object('old', OLD.name, 'new', NEW.name));\r\n    END IF;\r\n    IF OLD.price IS DISTINCT FROM NEW.price THEN\r\n      v_changes := v_changes || jsonb_build_object('price', jsonb_build_object('old', OLD.price, 'new', NEW.price));\r\n    END IF;\r\n    IF OLD.cost_price IS DISTINCT FROM NEW.cost_price THEN\r\n      v_changes := v_changes || jsonb_build_object('cost_price', jsonb_build_object('old', OLD.cost_price, 'new', NEW.cost_price));\r\n    END IF;\r\n    IF OLD.stock_quantity IS DISTINCT FROM NEW.stock_quantity THEN\r\n      v_changes := v_changes || jsonb_build_object('stock_quantity', jsonb_build_object('old', OLD.stock_quantity, 'new', NEW.stock_quantity));\r\n    END IF;\r\n    IF OLD.is_active IS DISTINCT FROM NEW.is_active THEN\r\n      v_changes := v_changes || jsonb_build_object('is_active', jsonb_build_object('old', OLD.is_active, 'new', NEW.is_active));\r\n    END IF;\r\n    \r\n    -- Se houve mudanças, registra\r\n    IF v_changes != '{}'::jsonb THEN\r\n      v_old_data := to_jsonb(OLD);\r\n      v_new_data := to_jsonb(NEW);\r\n      \r\n      INSERT INTO system_logs (\r\n        user_id, user_email, user_role, action, entity_type,\r\n        entity_id, old_data, new_data, details\r\n      ) VALUES (\r\n        auth.uid(),\r\n        (SELECT email FROM profiles WHERE id = auth.uid()),\r\n        (SELECT role FROM profiles WHERE id = auth.uid()),\r\n        'UPDATE',\r\n        'product',\r\n        NEW.id::text,\r\n        v_old_data,\r\n        v_new_data,\r\n        jsonb_build_object('changes', v_changes)\r\n      );\r\n    END IF;\r\n  END IF;\r\n  \r\n  RETURN NEW;\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.get_stock_movements_summary(p_start_date date DEFAULT (CURRENT_DATE - '30 days'::interval), p_end_date date DEFAULT CURRENT_DATE)\n RETURNS jsonb\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nBEGIN\r\n  RETURN (\r\n    SELECT jsonb_build_object(\r\n      'total_in', COALESCE(SUM(quantity) FILTER (WHERE quantity > 0), 0),\r\n      'total_out', COALESCE(SUM(ABS(quantity)) FILTER (WHERE quantity < 0), 0),\r\n      'by_type', (\r\n        SELECT jsonb_object_agg(movement_type, COUNT(*))\r\n        FROM public.stock_movements\r\n        WHERE DATE(created_at) BETWEEN p_start_date AND p_end_date\r\n        GROUP BY movement_type\r\n      ),\r\n      'by_reference', (\r\n        SELECT jsonb_object_agg(reference_type, COUNT(*))\r\n        FROM public.stock_movements\r\n        WHERE DATE(created_at) BETWEEN p_start_date AND p_end_date\r\n        GROUP BY reference_type\r\n      ),\r\n      'top_moved_products', (\r\n        SELECT jsonb_agg(\r\n          jsonb_build_object(\r\n            'product_id', product_id,\r\n            'total_movements', COUNT(*),\r\n            'total_quantity', SUM(ABS(quantity))\r\n          )\r\n        )\r\n        FROM public.stock_movements\r\n        WHERE DATE(created_at) BETWEEN p_start_date AND p_end_date\r\n        GROUP BY product_id\r\n        ORDER BY SUM(ABS(quantity)) DESC\r\n        LIMIT 10\r\n      )\r\n    )\r\n    FROM public.stock_movements\r\n    WHERE DATE(created_at) BETWEEN p_start_date AND p_end_date\r\n  );\r\nEND;\r\n$function$\n;"
  },
  {
    "function_definition": "CREATE OR REPLACE FUNCTION public.fix_product_stock_consistency(p_product_id bigint)\n RETURNS void\n LANGUAGE plpgsql\n SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_calculated_stock numeric;\r\n  v_current_stock numeric;\r\nBEGIN\r\n  -- Verificar permissão\r\n  IF NOT EXISTS (\r\n    SELECT 1 FROM public.profiles \r\n    WHERE id = auth.uid() \r\n    AND role = 'admin'\r\n  ) THEN\r\n    RAISE EXCEPTION 'Apenas administradores podem corrigir inconsistências de estoque';\r\n  END IF;\r\n  \r\n  -- Calcular estoque baseado no histórico de movimentações\r\n  SELECT COALESCE(SUM(quantity), 0) INTO v_calculated_stock\r\n  FROM public.stock_movements\r\n  WHERE product_id = p_product_id;\r\n  \r\n  -- Buscar estoque atual\r\n  SELECT stock_quantity INTO v_current_stock\r\n  FROM public.products\r\n  WHERE id = p_product_id;\r\n  \r\n  -- Se houver divergência, registrar ajuste\r\n  IF v_calculated_stock != v_current_stock THEN\r\n    -- Registrar movimentação de correção\r\n    INSERT INTO public.stock_movements (\r\n      product_id,\r\n      movement_type,\r\n      quantity,\r\n      quantity_before,\r\n      quantity_after,\r\n      reference_type,\r\n      reason,\r\n      created_by\r\n    ) VALUES (\r\n      p_product_id,\r\n      'correction',\r\n      v_calculated_stock - v_current_stock,\r\n      v_current_stock,\r\n      v_calculated_stock,\r\n      'adjustment',\r\n      'Correção automática de inconsistência de estoque',\r\n      auth.uid()\r\n    );\r\n    \r\n    -- Atualizar estoque\r\n    UPDATE public.products\r\n    SET \r\n      stock_quantity = v_calculated_stock,\r\n      updated_at = now(),\r\n      updated_by = auth.uid()\r\n    WHERE id = p_product_id;\r\n  END IF;\r\nEND;\r\n$function$\n;"
  }
]